t;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathrm&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathrm&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathrm&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;v&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;其中 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;u&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mrow&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;a&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;d&lt;/mi&gt;&lt;mi mathvariant=&#34;normal&#34;&gt;j&lt;/mi&gt;&lt;/mrow&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;msub&gt;&lt;mi&gt;v&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;u_i\ \mathrm{adj}\ v_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8888799999999999em;vertical-align:-0.19444em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;u&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathrm&#34;&gt;a&lt;/span&gt;&lt;span class=&#34;mord mathrm&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mord mathrm&#34;&gt;j&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;v&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03588em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 表示 u&lt;sub&gt;i&lt;/sub&gt; 和 v&lt;sub&gt;i&lt;/sub&gt; 邻接。&lt;/p&gt;
&lt;p&gt;就把 u 和 v 连接起来所得到的图 G 称为 G&lt;sub&gt;1&lt;/sub&gt; 和 G&lt;sub&gt;2&lt;/sub&gt; 的&lt;strong&gt;积图&lt;/strong&gt;，记为 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;mo&gt;×&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;G&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;G=G_1 \times G_2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;×&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;G&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;系统的描述&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#系统的描述&#34;&gt;#&lt;/a&gt; 系统的描述&lt;/h1&gt;
&lt;h2 id=&#34;两种描述方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#两种描述方法&#34;&gt;#&lt;/a&gt; 两种描述方法&lt;/h2&gt;
&lt;h3 id=&#34;输入输出描述法-微分方程-差分方程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入输出描述法-微分方程-差分方程&#34;&gt;#&lt;/a&gt; 输入输出描述法 (微分方程、差分⽅程)&lt;/h3&gt;
&lt;p&gt;着眼于系统输入与输出的关系，适⽤用于单输入 — 单输出系统。&lt;/p&gt;
&lt;h3 id=&#34;状态变量描述法-状态方程-输出方程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#状态变量描述法-状态方程-输出方程&#34;&gt;#&lt;/a&gt; 状态变量描述法 (状态⽅程、输出方程)&lt;/h3&gt;
&lt;p&gt;即可描述输入与输出的关系，还可以描述系统的内部状态 既可⽤用于单输入 — 单输出系统，⼜可⽤于多输⼊ — 多输出系统。&lt;/p&gt;
&lt;h2 id=&#34;系统的组成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#系统的组成&#34;&gt;#&lt;/a&gt; 系统的组成&lt;/h2&gt;
&lt;p&gt;⼀个系统由若⼲个基本单元组成， 其中的基本组成单元包括:&lt;/p&gt;
&lt;h3 id=&#34;加法器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#加法器&#34;&gt;#&lt;/a&gt; 加法器&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/signals-and-systems/systems-concepts/%E5%8A%A0%E6%B3%95%E5%99%A8.png&#34; alt=&#34;加法器&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;数乘器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数乘器&#34;&gt;#&lt;/a&gt; 数乘器&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/signals-and-systems/systems-concepts/%E6%95%B0%E4%B9%98%E5%99%A8.png&#34; alt=&#34;数乘器&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;积分器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#积分器&#34;&gt;#&lt;/a&gt; 积分器&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/signals-and-systems/systems-concepts/%E7%A7%AF%E5%88%86%E5%99%A8.png&#34; alt=&#34;积分器&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;单位延时器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#单位延时器&#34;&gt;#&lt;/a&gt; 单位延时器&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/signals-and-systems/systems-concepts/%E5%8D%95%E4%BD%8D%E5%BB%B6%E6%97%B6%E5%99%A8.png&#34; alt=&#34;单位延时器&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;延时器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#延时器&#34;&gt;#&lt;/a&gt; 延时器&lt;/h3&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/signals-and-systems/systems-concepts/%E5%BB%B6%E6%97%B6%E5%99%A8.png&#34; alt=&#34;延时器&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;根据系统框图描述建立微分方程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#根据系统框图描述建立微分方程&#34;&gt;#&lt;/a&gt; 根据系统框图描述建立微分方程&lt;/h2&gt;
&lt;h3 id=&#34;对于连续系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#对于连续系统&#34;&gt;#&lt;/a&gt; 对于连续系统&lt;/h3&gt;
&lt;p&gt;步骤如下&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;首先判断其阶数，阶数 = 积分器个数&lt;/li&gt;
&lt;li&gt;设信号传递&lt;strong&gt;最后一个积分器输出为 &lt;em&gt;x&lt;/em&gt;(&lt;em&gt;t&lt;/em&gt;)&lt;/strong&gt; ，则各积分器的输入输出均可确定&lt;/li&gt;
&lt;li&gt;对每个加法器列⽅程：输入和 = 输出和&lt;/li&gt;
&lt;li&gt;联立方程消去中间变量 &lt;em&gt;x&lt;/em&gt;(&lt;em&gt;t&lt;/em&gt;) ，得到关于输出信号 &lt;em&gt;y&lt;/em&gt;(&lt;em&gt;t&lt;/em&gt;) 的微分方程&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;对于离散系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#对于离散系统&#34;&gt;#&lt;/a&gt; 对于离散系统&lt;/h3&gt;
&lt;p&gt;步骤如下&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;逻辑代数中的基本运算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑代数中的基本运算&#34;&gt;#&lt;/a&gt; 逻辑代数中的基本运算&lt;/h1&gt;
&lt;h2 id=&#34;三种基本运算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三种基本运算&#34;&gt;#&lt;/a&gt; 三种基本运算&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E4%B8%89%E7%A7%8D%E5%9F%BA%E6%9C%AC%E8%BF%90%E7%AE%97.png&#34; alt=&#34;三种基本运算&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;真值表&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#真值表&#34;&gt;#&lt;/a&gt; 真值表&lt;/h2&gt;
&lt;p&gt;表征逻辑事件输入（条件）和输出（结果）之间全部可能状态的表格&lt;/p&gt;
&lt;p&gt;真值表表示与、或、非运算：&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E4%B8%8E%E6%88%96%E9%9D%9E.png&#34; alt=&#34;与或非&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;其他复合逻辑运算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#其他复合逻辑运算&#34;&gt;#&lt;/a&gt; 其他复合逻辑运算&lt;/h2&gt;
&lt;h3 id=&#34;与非&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#与非&#34;&gt;#&lt;/a&gt; 与非&lt;/h3&gt;
&lt;p&gt;“先与再非”&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E4%B8%8E%E9%9D%9E.png&#34; alt=&#34;与非&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;或非&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#或非&#34;&gt;#&lt;/a&gt; 或非&lt;/h3&gt;
&lt;p&gt;“先或再非”&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E6%88%96%E9%9D%9E.png&#34; alt=&#34;或非&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;与或非&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#与或非&#34;&gt;#&lt;/a&gt; 与或非&lt;/h3&gt;
&lt;p&gt;“先与再或再非”&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E4%B8%8E%E6%88%96%E9%9D%9E.png&#34; alt=&#34;与或非&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;异或-xor&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#异或-xor&#34;&gt;#&lt;/a&gt; 异或 XOR&lt;/h3&gt;
&lt;p&gt;不同时输出 1，相同时输出 0&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/XOR.png&#34; alt=&#34;XOR&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;同或&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#同或&#34;&gt;#&lt;/a&gt; 同或&lt;/h3&gt;
&lt;p&gt;同或 —— 相同时输出 1，不同时输出 0&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E5%90%8C%E6%88%96.png&#34; alt=&#34;同或&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;逻辑代数的公式和定理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑代数的公式和定理&#34;&gt;#&lt;/a&gt; 逻辑代数的公式和定理&lt;/h1&gt;
&lt;h2 id=&#34;逻辑代数的基本公式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑代数的基本公式&#34;&gt;#&lt;/a&gt; 逻辑代数的基本公式&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E9%80%BB%E8%BE%91%E4%BB%A3%E6%95%B0%E7%9A%84%E5%9F%BA%E6%9C%AC%E5%85%AC%E5%BC%8F1.png&#34; alt=&#34;逻辑代数的基本公式1&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E9%80%BB%E8%BE%91%E4%BB%A3%E6%95%B0%E7%9A%84%E5%9F%BA%E6%9C%AC%E5%85%AC%E5%BC%8F2.png&#34; alt=&#34;逻辑代数的基本公式2&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;常考公式-717-分配律&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常考公式-717-分配律&#34;&gt;#&lt;/a&gt; 常考公式 7/17 分配律&lt;/h3&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mspace linebreak=&#34;newline&#34;&gt;&lt;/mspace&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A(B +C) = AB + AC\\ A + BC = (A +B)(A +C)
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace newline&#34;&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;用途：将 “混杂” 在一起的变量分离，将逻辑函数表达式化成 “与或” 形式和 “或与” 形式；在后面逻辑函数的 “最小项之和” 和 “最大项之积” 表示时非常有用&lt;/p&gt;
&lt;h3 id=&#34;常考公式-818-反演律德摩根定律&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常考公式-818-反演律德摩根定律&#34;&gt;#&lt;/a&gt; 常考公式 8/18 反演律（德・摩根定律）&lt;/h3&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;msup&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;msup&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;(AB)&amp;#x27; = A&amp;#x27; + B&amp;#x27; (A + B) &amp;#x27; = A&amp;#x27;B&amp;#x27;
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.051892em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.801892em;&#34;&gt;&lt;span style=&#34;top:-3.113em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8852220000000001em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.801892em;&#34;&gt;&lt;span style=&#34;top:-3.113em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.051892em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.801892em;&#34;&gt;&lt;span style=&#34;top:-3.113em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.051892em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.801892em;&#34;&gt;&lt;span style=&#34;top:-3.113em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.801892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.801892em;&#34;&gt;&lt;span style=&#34;top:-3.113em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.801892em;&#34;&gt;&lt;span style=&#34;top:-3.113em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;记忆方法：“与的非等于非的或，或的非等于非的与”&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;与在概率论课程中学习的德摩根定律一致，即 “交的反等于反的并，并的反等于反的交”&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;用途：实现与运算和或运算之间的转换，在后面对函数式进行特定形式的变换时非常有用&lt;/p&gt;
&lt;h2 id=&#34;逻辑代数的基本定理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑代数的基本定理&#34;&gt;#&lt;/a&gt; 逻辑代数的基本定理&lt;/h2&gt;
&lt;h3 id=&#34;代入定理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#代入定理&#34;&gt;#&lt;/a&gt; 代入定理&lt;/h3&gt;
&lt;p&gt;在任何一个包含 A 的逻辑等式中，若以另外一个逻辑式代入式中 A 的位置，则等式依然成立；&lt;/p&gt;
&lt;h3 id=&#34;反演定理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#反演定理&#34;&gt;#&lt;/a&gt; 反演定理&lt;/h3&gt;
&lt;p&gt;对任一逻辑式 Y ，在求解它的反时（即已知 Y 求解 Y’），只需要在保证运算优先次序不变的原则下，将其中所有的 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cdot&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.44445em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;⋅&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 换成 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;+&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;+&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;+&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;+&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 换成 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cdot&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.44445em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;⋅&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; ，原变量换成反变量，反变量换成原变量（不属于单个变量上的反号不动），1 变成 0，0 变成 1，得到的结果就是 Y’；&lt;/p&gt;
&lt;h3 id=&#34;对偶定理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#对偶定理&#34;&gt;#&lt;/a&gt; 对偶定理&lt;/h3&gt;
&lt;p&gt;若两逻辑表达式相等，则它们的对偶式也相等；&lt;/p&gt;
&lt;p&gt;所谓的对偶式指的是在保持运算优先顺序不变的原则下，将表达式中所有的 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cdot&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.44445em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;⋅&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 换成 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;+&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;+&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;+&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.66666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;+&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 换成 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\cdot&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.44445em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;⋅&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; ，0 换成 1，1 换成 0；&lt;/p&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;注意与反演定理的区别！变量不取反！&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;主要应用于证明题当中，证明两个形式较复杂的逻辑式相等，可以尝试：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;两边同时取对偶式，证明它们的对偶式相等&lt;/li&gt;
&lt;li&gt;对等号某一侧表达式先取对偶式，对对偶式进行化简之后，再取对偶就可以得到等号另一侧表达式&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;逻辑函数及其表示方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数及其表示方法&#34;&gt;#&lt;/a&gt; 逻辑函数及其表示方法&lt;/h1&gt;
&lt;p&gt;以逻辑变量为输入，运算结果为输出，则输入变量值确定以后，输出的取值也随之而定，因此输入 — 输出之间是一种函数关系，称作逻辑函数；&lt;/p&gt;
&lt;p&gt;在我们学习的二值逻辑 (布尔逻辑) 中，输入变量和输出变量只有 0 和 1 两种状态；&lt;/p&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;在求解实际应用问题中的逻辑函数关系时，首先必须做的事情是将具体事物抽象为逻辑变量并规定其不同状态（0 或 1），这是很重要的解题习惯，类似于在概率论答题时首先要记不同的事件为 A、B……；这里只研究现有的抽象后的逻辑函数式；&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;逻辑函数的不同表示方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数的不同表示方法&#34;&gt;#&lt;/a&gt; 逻辑函数的不同表示方法&lt;/h2&gt;
&lt;h3 id=&#34;真值表-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#真值表-2&#34;&gt;#&lt;/a&gt; 真值表&lt;/h3&gt;
&lt;p&gt;遍历输入变量所有取值下的输出值，列成表格&lt;/p&gt;
&lt;h3 id=&#34;逻辑函数式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数式&#34;&gt;#&lt;/a&gt; 逻辑函数式&lt;/h3&gt;
&lt;p&gt;将输出写成输入变量的与、或、非等逻辑运算的组合式&lt;/p&gt;
&lt;h3 id=&#34;逻辑图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑图&#34;&gt;#&lt;/a&gt; 逻辑图&lt;/h3&gt;
&lt;p&gt;逻辑函数式用图形符号表示&lt;/p&gt;
&lt;h3 id=&#34;波形图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#波形图&#34;&gt;#&lt;/a&gt; 波形图&lt;/h3&gt;
&lt;p&gt;输入变量所有取值可能与对应输出的时域波形&lt;/p&gt;
&lt;h3 id=&#34;卡诺图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#卡诺图&#34;&gt;#&lt;/a&gt; 卡诺图&lt;/h3&gt;
&lt;h3 id=&#34;计算机软件中的描述方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算机软件中的描述方式&#34;&gt;#&lt;/a&gt; 计算机软件中的描述方式&lt;/h3&gt;
&lt;p&gt;例如 Verilog 语言&lt;/p&gt;
&lt;h2 id=&#34;逻辑函数不同表示方法间的转换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数不同表示方法间的转换&#34;&gt;#&lt;/a&gt; 逻辑函数不同表示方法间的转换&lt;/h2&gt;
&lt;h3 id=&#34;真值表-逻辑函数式-重点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#真值表-逻辑函数式-重点&#34;&gt;#&lt;/a&gt; 真值表 -&amp;gt; 逻辑函数式 (重点)&lt;/h3&gt;
&lt;p&gt;(逻辑函数的最小项之和形式)&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;找出真值表中使逻辑函数输出 Y = 1 的输入变量取值的组合即使 Y = 1 的行；&lt;/li&gt;
&lt;li&gt;使 Y = 1 的每组输入变量取值的组合（即每一行）对应一个乘积项，取值为 1 写入原变量，取值为 0 写入反变量；&lt;/li&gt;
&lt;li&gt;将各行对应的乘积项相加，即最终结果为 “与或” 形式；&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;逻辑函数式-逻辑图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数式-逻辑图&#34;&gt;#&lt;/a&gt; 逻辑函数式 &amp;lt;-&amp;gt; 逻辑图&lt;/h3&gt;
&lt;h4 id=&#34;逻辑函数式-逻辑图-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数式-逻辑图-2&#34;&gt;#&lt;/a&gt; 逻辑函数式 -&amp;gt; 逻辑图&lt;/h4&gt;
&lt;p&gt;用图形符号代替逻辑函数式中的逻辑运算符；&lt;/p&gt;
&lt;h4 id=&#34;逻辑图-逻辑函数式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑图-逻辑函数式&#34;&gt;#&lt;/a&gt; 逻辑图 -&amp;gt; 逻辑函数式&lt;/h4&gt;
&lt;p&gt;从输入到输出逐级写出每个图形符号对应的逻辑运算式；&lt;/p&gt;
&lt;h3 id=&#34;真值表-波形图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#真值表-波形图&#34;&gt;#&lt;/a&gt; 真值表 &amp;lt;-&amp;gt; 波形图&lt;/h3&gt;
&lt;h4 id=&#34;真值表-波形图-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#真值表-波形图-2&#34;&gt;#&lt;/a&gt; 真值表 -&amp;gt; 波形图&lt;/h4&gt;
&lt;p&gt;将所有输入变量与对应输出变量的取值依次排列，以时间为横轴；&lt;/p&gt;
&lt;h4 id=&#34;波形图-真值表&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#波形图-真值表&#34;&gt;#&lt;/a&gt; 波形图 -&amp;gt; 真值表&lt;/h4&gt;
&lt;p&gt;在波形图中找出每个时间段里输入变量与输出变量的取值列成表格（ 对于 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;N&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个输入变量要对应 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;2^N&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8413309999999999em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8413309999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个组合即 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;2^N&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8413309999999999em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8413309999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 行）&lt;/p&gt;
&lt;h2 id=&#34;逻辑函数的-标准规范-形式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数的-标准规范-形式&#34;&gt;#&lt;/a&gt; 逻辑函数的 标准 / 规范 形式&lt;/h2&gt;
&lt;h3 id=&#34;dnf&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dnf&#34;&gt;#&lt;/a&gt; DNF&lt;/h3&gt;
&lt;p&gt;别名：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;最小项标准式&lt;/li&gt;
&lt;li&gt;析取范式&lt;/li&gt;
&lt;li&gt;积之和范式&lt;/li&gt;
&lt;li&gt;与或范式&lt;/li&gt;
&lt;li&gt;disjunctive normal form (DNF)&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;任何一个逻辑函数式都可以化为若干个最小项之和的形式&lt;/p&gt;
&lt;h4 id=&#34;最小项-m-的定义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最小项-m-的定义&#34;&gt;#&lt;/a&gt; 最小项 &lt;em&gt;m&lt;/em&gt; 的定义：&lt;/h4&gt;
&lt;p&gt;&lt;em&gt;m&lt;/em&gt; 是乘积项，包含 &lt;em&gt;n&lt;/em&gt; 个因子，&lt;em&gt;n&lt;/em&gt; 个变量均以原变量或反变量的形式在 &lt;em&gt;m&lt;/em&gt; 中出现一次；&lt;/p&gt;
&lt;h4 id=&#34;最小项的特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最小项的特点&#34;&gt;#&lt;/a&gt; 最小项的特点&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;全体最小项之和为 1&lt;/li&gt;
&lt;li&gt;各个最小项之间是互斥的，即任何两个最小项之积为 0 ；换句话说，对于任何一个特定的输入变量取值，有且仅有一个最小项为 1；&lt;/li&gt;
&lt;li&gt;两个相邻的最小项之和可以合并，消去一对因子，只留下公共因子；&lt;/li&gt;
&lt;/ul&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;这里的 “相邻” 不是按照自然二进制数编号后的相邻，而是指逻辑上的相邻，规定仅一个变量不同的最小项彼此称为相邻；&lt;/p&gt;
&lt;p&gt;例如 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;msup&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A&amp;#x27; B&amp;#x27; C&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;、 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A&amp;#x27;BC&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;、 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A&amp;#x27;BC&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;  即 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 、&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 、&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;3&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_3&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;3&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;， &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 和 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 不是相邻，&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 和 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;3&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_3&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;3&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 才是相邻；&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 和 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mn&gt;3&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;m_3&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.58056em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;3&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 可以合并消去因子 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;B+B&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;h4 id=&#34;转化为dnf&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#转化为dnf&#34;&gt;#&lt;/a&gt; 转化为 DNF&lt;/h4&gt;
&lt;p&gt;事实上最小项就是在列写 &lt;em&gt;n&lt;/em&gt; 个输入变量的逻辑函数的真值表时每一行对应的输入变量的乘积项，取值为 1 写入原变量，取值为 0 写入反变量；使最小项取值为 1 的变量取值，按照 &lt;em&gt;n&lt;/em&gt; 位自然二进制数排列后对应的十进制数就是这个最小项的编号&lt;/p&gt;
&lt;h3 id=&#34;cnf&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cnf&#34;&gt;#&lt;/a&gt; CNF&lt;/h3&gt;
&lt;p&gt;别名：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;最大项标准式&lt;/li&gt;
&lt;li&gt;合取范式&lt;/li&gt;
&lt;li&gt;和之积范式&lt;/li&gt;
&lt;li&gt;或与范式&lt;/li&gt;
&lt;li&gt;conjunctive normal form (CNF)&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;任何一个逻辑函数式都可以化为若干个最大项之积的形式&lt;/p&gt;
&lt;h4 id=&#34;最大项-m-的定义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最大项-m-的定义&#34;&gt;#&lt;/a&gt; 最大项 &lt;em&gt;M&lt;/em&gt; 的定义&lt;/h4&gt;
&lt;p&gt;&lt;em&gt;M&lt;/em&gt; 是相加项，包含 &lt;em&gt;n&lt;/em&gt; 个因子，&lt;em&gt;n&lt;/em&gt; 个变量均以原变量和反变量的形式在 &lt;em&gt;M&lt;/em&gt; 中出现一次；可以把最大项看作是对每一个最小项应用反演定理，因此，最大项的编号原则是反的，即原变量记为 0，反变量记为 1，&lt;em&gt;n&lt;/em&gt; 位自然二进制数排列后对应的十进制数为编号；&lt;/p&gt;
&lt;p&gt;例如 &lt;em&gt;A+B+C′&lt;/em&gt; 的编号是 001 即 &lt;em&gt;M&lt;/em&gt;1 ；&lt;/p&gt;
&lt;p&gt;（记忆方法：对于与运算即乘积项，得 1 “容易”，即得 1 时输入变量组唯一确定；对于或运算即相加项，得 0 “容易”，即得 0 时输入变量组唯一确定；）&lt;/p&gt;
&lt;h4 id=&#34;最大项的特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最大项的特点&#34;&gt;#&lt;/a&gt; 最大项的特点&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;全体最大项之积为 0 ;&lt;/li&gt;
&lt;li&gt;任何两个最大项之和为 1 ；换句话说，对于任何一个特定的输入变量取值，有且仅有一个最小项为 0；&lt;/li&gt;
&lt;li&gt;两个相邻的最大项之积保留公共变量&lt;/li&gt;
&lt;/ul&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;这里的相邻和前面最小项的相邻一致，都是指逻辑上的相邻，即只有一个变量不同。&lt;/p&gt;
&lt;p&gt;例如 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A+B+C&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 和 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A+B&amp;#x27;+C&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.835222em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 为相邻，即 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;M_1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.10903em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 和 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mn&gt;3&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;M_3&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.10903em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;3&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 相邻，两者的乘积项即相与的结果是 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A+C&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; ；&lt;/p&gt;
&lt;/div&gt;
&lt;h4 id=&#34;转化为cnf&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#转化为cnf&#34;&gt;#&lt;/a&gt; 转化为 CNF&lt;/h4&gt;
&lt;p&gt;当给定的逻辑函数式不是标准的最大项之积的形式时，一般不断地利用 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A\cdot A&amp;#x27;=0&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;⋅&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 补全缺少的因子，并结合分配律 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A + BC = (A +B)(A +C)&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 将与或形式转化为或与形式；&lt;/p&gt;
&lt;h3 id=&#34;最小项与最大项的关系&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最小项与最大项的关系&#34;&gt;#&lt;/a&gt; 最小项与最大项的关系&lt;/h3&gt;
&lt;p&gt;根据最大项和最小项的定义以及德・摩根定理，易推导得到：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;msubsup&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msubsup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;M_i=m&amp;#x27;_i
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.10903em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.048892em;vertical-align:-0.247em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8018919999999999em;&#34;&gt;&lt;span style=&#34;top:-2.4530000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.113em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.247em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;如果将逻辑函数写成最小项之和的形式：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;munder&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mo&gt;∈&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;R&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;/munder&gt;&lt;msub&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum_{i\in R_1} m_i
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:2.4444410000000003em;vertical-align:-1.394436em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-limits&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.050005em;&#34;&gt;&lt;span style=&#34;top:-1.855664em;margin-left:0em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3.05em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;∈&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.00773em;&#34;&gt;R&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31731428571428577em;&#34;&gt;&lt;span style=&#34;top:-2.357em;margin-left:-0.00773em;margin-right:0.07142857142857144em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.5em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size3 size1 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.143em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.0500049999999996em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3.05em;&#34;&gt;&lt;/span&gt;&lt;span&gt;&lt;span class=&#34;mop op-symbol large-op&#34;&gt;∑&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.394436em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:0em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;再将其写成最大项之积的形式：&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;munder&gt;&lt;mo&gt;∏&lt;/mo&gt;&lt;mrow&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mo&gt;∈&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;R&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;/munder&gt;&lt;msub&gt;&lt;mi&gt;M&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\prod_{i\in R_2} M_i
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:2.4444410000000003em;vertical-align:-1.394436em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-limits&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.050005em;&#34;&gt;&lt;span style=&#34;top:-1.855664em;margin-left:0em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3.05em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;span class=&#34;mrel mtight&#34;&gt;∈&lt;/span&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.00773em;&#34;&gt;R&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31731428571428577em;&#34;&gt;&lt;span style=&#34;top:-2.357em;margin-left:-0.00773em;margin-right:0.07142857142857144em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.5em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size3 size1 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.143em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.0500049999999996em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3.05em;&#34;&gt;&lt;/span&gt;&lt;span&gt;&lt;span class=&#34;mop op-symbol large-op&#34;&gt;∏&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:1.394436em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;M&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.10903em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;则两者的下标编号集合 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;R&lt;/mi&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;R_1&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.00773em;&#34;&gt;R&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.00773em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;1&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 和 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;R&lt;/mi&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;R_2&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.83333em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.00773em;&#34;&gt;R&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.30110799999999993em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.00773em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;2&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 是互补的。&lt;/p&gt;
&lt;p&gt;所以很多时候不需要直接展开求解最大项之积，先求解最小项之和更方便&lt;/p&gt;
&lt;h1 id=&#34;逻辑函数的化简&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数的化简&#34;&gt;#&lt;/a&gt; 逻辑函数的化简&lt;/h1&gt;
&lt;h2 id=&#34;逻辑函数的化简的目标&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑函数的化简的目标&#34;&gt;#&lt;/a&gt; 逻辑函数的化简的目标&lt;/h2&gt;
&lt;p&gt;逻辑函数的最小项之和虽然是通用的标准形式，但不一定就是最简的；在实际数字逻辑电路设计时，需要考虑在逻辑功能相同的条件下使用尽可能简单的电路，即电子器件数量足够少；&lt;/p&gt;
&lt;p&gt;事实上，没有绝对的最简，由于我们习惯性将逻辑函数写成 最小项之和 即 与或形式 ，因此对于 与或形式 的逻辑函数，包含的乘积项最少，且每个乘积项里的因子也不能再减少时，称其为最简形式即最简与或形式；其他形式的最简同理；&lt;/p&gt;
&lt;p&gt;常考最简式包括：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;最简与或式&lt;/li&gt;
&lt;li&gt;最简或与式&lt;/li&gt;
&lt;li&gt;最简与非 — 与非式&lt;/li&gt;
&lt;li&gt;最简或非 — 或非式&lt;/li&gt;
&lt;li&gt;最简与或非式&lt;/li&gt;
&lt;/ul&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;实际的逻辑电路设计可能会受到电子器件种类与数量的限制，因此可能要进行变换；直接用卡诺图化简得到的最简与或式并不一定是设计时需要的逻辑函数形式，所以还会需要其他最简形式，例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;只能用或非门实现：与非 — 与非式&lt;/li&gt;
&lt;li&gt;只能用或非门实现：或非 — 或非式&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;h2 id=&#34;公式化简法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#公式化简法&#34;&gt;#&lt;/a&gt; 公式化简法&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;使用前面学习的基本公式和常用公式&lt;/li&gt;
&lt;li&gt;没有固定的步骤，&lt;/li&gt;
&lt;li&gt;难以确定结果正确与否&lt;/li&gt;
&lt;li&gt;不通用但有时很快速好用&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;对公式化简法，要求掌握但不必深入研究，熟悉教材上的例题和课后题即可；&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;一个可能会用到公式化简法的情况是，当逻辑函数含有变量数很多时，即很难直接采用卡诺图去进行化简时，一般题目的设计会使解题时经常需要用 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;mi&gt;D&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;B&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;msup&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;mi&gt;C&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;AB + A&amp;#x27;C + BCD = AB + A&amp;#x27;C&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.835222em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;D&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.05017em;&#34;&gt;B&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;C&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 这个公式来消去多余的变量，接着再用卡诺图去进行化简&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;卡诺图化简法-重点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#卡诺图化简法-重点&#34;&gt;#&lt;/a&gt; 卡诺图化简法 (重点)&lt;/h2&gt;
&lt;h3 id=&#34;卡诺图是什么&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#卡诺图是什么&#34;&gt;#&lt;/a&gt; 卡诺图是什么&lt;/h3&gt;
&lt;p&gt;以 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;2^n&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.664392em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.664392em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;n&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个小方块分别代表 &lt;em&gt;n&lt;/em&gt; 变量的所有最小项，并将它们排列成矩阵，而且使几何位置相邻的两个最小项在逻辑上也是相邻的（只有一个变量不同），就得到表示 &lt;em&gt;n&lt;/em&gt; 变量全部最小项的卡诺图；&lt;/p&gt;
&lt;h3 id=&#34;卡诺图的绘制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#卡诺图的绘制&#34;&gt;#&lt;/a&gt; 卡诺图的绘制&lt;/h3&gt;
&lt;p&gt;横纵轴不是按照自然二进制数排列，按照格雷码排列，目的是为了使逻辑上相邻对应几何上相邻，保证相邻的方块只有一个变量不同&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E5%8D%A1%E8%AF%BA%E5%9B%BE%E7%9A%84%E7%BB%98%E5%88%B6.png&#34; alt=&#34;卡诺图的绘制&#34; /&gt;&lt;/p&gt;
&lt;p&gt;记忆方法：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;增加一个变量看作是折纸一样翻折&lt;/li&gt;
&lt;li&gt;轴对称位置上的最小项也满足相邻&lt;/li&gt;
&lt;li&gt;把卡诺图看作是闭合的图形 (横纵轴都是循环的)&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;教材上的卡诺图并不是唯一的，只要能够保证&lt;strong&gt;逻辑对称性&lt;/strong&gt;与&lt;strong&gt;几何对称性&lt;/strong&gt;一致即可，最好去理解卡诺图绘制的过程&lt;/p&gt;
&lt;h3 id=&#34;卡诺图化简法的本质&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#卡诺图化简法的本质&#34;&gt;#&lt;/a&gt; 卡诺图化简法的本质&lt;/h3&gt;
&lt;p&gt;将最小项之和用图形描述，将逻辑上的相邻表现为几何图形的相邻，通过合并相邻的几何图形，合并后对应仅保留公共因子的最小项，最终结果就是&lt;strong&gt;最简与或式&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;卡诺图化简逻辑函数的步骤&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#卡诺图化简逻辑函数的步骤&#34;&gt;#&lt;/a&gt; 卡诺图化简逻辑函数的步骤&lt;/h3&gt;
&lt;h4 id=&#34;最简与或式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最简与或式&#34;&gt;#&lt;/a&gt; 最简与或式&lt;/h4&gt;
&lt;p&gt;若只给出逻辑函数则从步骤 1 开始，若给出卡诺图则直接从步骤 2 开始&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;将逻辑函数写成最小项之和的形式&lt;/li&gt;
&lt;li&gt;根据最小项之和绘制对应的卡诺图，逻辑函数式中含有的最小项的对应位置填 1，其余的位置填 0&lt;/li&gt;
&lt;li&gt;合并相邻的最小项，对应最终结果为 最简与或式&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;ul&gt;
&lt;li&gt;相邻表示逻辑相邻，轴对称位置上的方块也可合并&lt;/li&gt;
&lt;li&gt;合并时，每个方块可以重复使用，因为 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;A+A=A&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.76666em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;合并的原则是&lt;strong&gt;乘积项的数目最少，每个乘积项的因子最少&lt;/strong&gt;，即画的&lt;strong&gt;圈要尽量大&lt;/strong&gt;（消去尽量多的不同的因子），&lt;strong&gt;画圈的数目尽量少&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;结果不唯一，但乘积项的数目和每个乘积项的因子个数一致（这也是检查答案是否正确的依据）&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;h4 id=&#34;最简或与式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最简或与式&#34;&gt;#&lt;/a&gt; 最简或与式&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;对原逻辑函数 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 取反得到 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 采用上述卡诺图求最简与或式步骤得到 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的 最简与或式&lt;/li&gt;
&lt;li&gt;对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的 最简与或式 取反变换得到的 或与式 就是原逻辑函数 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的 最简或与式&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;或者直接：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;采用上述卡诺图求最简与或式步骤，但是合并为 0 的方块而不是 1 ，得到 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的最简与或式&lt;/li&gt;
&lt;li&gt;对 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;mo mathvariant=&#34;normal&#34; lspace=&#34;0em&#34; rspace=&#34;0em&#34;&gt;′&lt;/mo&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&amp;#x27;&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.751892em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.751892em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;′&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的 最简与或式 取反变换得到的 或与式 就是原逻辑函数 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;Y&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;Y&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.22222em;&#34;&gt;Y&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 的 最简或与式&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;最简与或非形式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最简与或非形式&#34;&gt;#&lt;/a&gt; 最简与或非形式&lt;/h4&gt;
&lt;p&gt;与最简或与式实际上是等价的，按照求最简或与式步骤即可，只是最后一步取反直接加上取反符号不需要再变换为或与式&lt;/p&gt;
&lt;h4 id=&#34;最简与非与非式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最简与非与非式&#34;&gt;#&lt;/a&gt; 最简与非 — 与非式&lt;/h4&gt;
&lt;p&gt;将得到的最简与或式取两次反，即逆向利用德・摩根定理&lt;/p&gt;
&lt;h4 id=&#34;最简或非或非形式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#最简或非或非形式&#34;&gt;#&lt;/a&gt; 最简或非 — 或非形式&lt;/h4&gt;
&lt;p&gt;将与或非形式中的每个乘积项再利用德・摩根定理，即变为或非形式&lt;/p&gt;
&lt;h3 id=&#34;含有无关项的卡诺图化简&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#含有无关项的卡诺图化简&#34;&gt;#&lt;/a&gt; 含有无关项的卡诺图化简&lt;/h3&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;一般第二章的题目会直接给出无关项，例如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;$ (...) + (...) +…… = 0 $&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mo&gt;…&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;0&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\sum d(…)= 0&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.00001em;vertical-align:-0.25001em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;minner&#34;&gt;…&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; （无关项 集合用 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;d&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;d&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;d&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 表示）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;后面在基于实际应用设计逻辑电路时应自行根据实际情况来分析确定无关项&lt;/p&gt;
&lt;/div&gt;
&lt;ol&gt;
&lt;li&gt;根据题意确定无关项&lt;/li&gt;
&lt;li&gt;绘制卡诺图时，无关项的方块用 × 表示&lt;/li&gt;
&lt;li&gt;化简时根据需要，将无关项填入 1 或 0 ，原则依然是是使化简后的项数最少，每项的因子最少，即&lt;strong&gt;画的圈最大，圈的个数最少&lt;/strong&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;编码的概念&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编码的概念&#34;&gt;#&lt;/a&gt; 编码的概念&lt;/h1&gt;
&lt;p&gt;广义的编码指的就是将信息从一种形式转换为另一种规范的形式；&lt;/p&gt;
&lt;p&gt;对于数字电路，就是将现实世界中的各种物理信息转换为离散的电压序列，来表示、处理和分析信息；&lt;/p&gt;
&lt;p&gt;事实上，进位计数制也是一种编码，用不同进制数来表示 “量”；&lt;/p&gt;
&lt;p&gt;将&lt;strong&gt;数制&lt;/strong&gt;与&lt;strong&gt;码制&lt;/strong&gt;分开介绍，首先单独讲解数制是因为数制的一个重要的特点是其编码后能够参与算术运算；而一般来说&lt;strong&gt;码制&lt;/strong&gt;是对&lt;strong&gt;非数值信息&lt;/strong&gt;的表示；&lt;/p&gt;
&lt;h1 id=&#34;常用编码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常用编码&#34;&gt;#&lt;/a&gt; 常用编码&lt;/h1&gt;
&lt;h2 id=&#34;常见十进制代码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常见十进制代码&#34;&gt;#&lt;/a&gt; 常见十进制代码&lt;/h2&gt;
&lt;div class=&#34;note primary&#34;&gt;
&lt;p&gt;十进制代码用四位二进制数（最多可表示 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mn&gt;2&lt;/mn&gt;&lt;mn&gt;4&lt;/mn&gt;&lt;/msup&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mn&gt;16&lt;/mn&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;2^4=16&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.8141079999999999em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.8141079999999999em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;4&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.64444em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;6&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 个）来表示 0~9&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E5%B8%B8%E8%A7%81%E5%8D%81%E8%BF%9B%E5%88%B6%E4%BB%A3%E7%A0%81.png&#34; alt=&#34;常见十进制代码&#34; /&gt;&lt;/p&gt;
&lt;p&gt;8421、2421、5211 每个数字指的是每个位的权；&lt;/p&gt;
&lt;p&gt;余 3 码是在 BCD 码即 8421 码的基础上加 3，即用 3~12 对应的二进制数来表示 0~9；&lt;/p&gt;
&lt;p&gt;余 3 循环码是取格雷码中的 3~12；&lt;/p&gt;
&lt;h2 id=&#34;格雷码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#格雷码&#34;&gt;#&lt;/a&gt; 格雷码&lt;/h2&gt;
&lt;p&gt;教材中的格雷码特指的是四位格雷码，即用四位代码来表示 0 ～ 15 共十六种状态；&lt;/p&gt;
&lt;h3 id=&#34;编码特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编码特点&#34;&gt;#&lt;/a&gt; 编码特点：&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;每一位的状态变化都按一定的顺序循环：0110、00111100、0000111111110000、0000000011111111（四位 16 个，只循环半个周期）（其他位数的格雷码表依次类推，自右向左每一位状态循环中连续的 0 和 1 数目加倍）&lt;/li&gt;
&lt;li&gt;按表中顺序变化时，相邻的代码只有一位改变状态，这是格雷码最大的特点和优点；（应用：减少代码转换过程中的过渡噪声）&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;四维格雷码表&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#四维格雷码表&#34;&gt;#&lt;/a&gt; 四维格雷码表&lt;/h3&gt;
&lt;p&gt;需要熟练掌握！重点是熟悉编码的规则和特点&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E5%9B%9B%E7%BB%B4%E6%A0%BC%E9%9B%B7%E7%A0%81%E8%A1%A8.png&#34; alt=&#34;四维格雷码表&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;ascii码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#ascii码&#34;&gt;#&lt;/a&gt; ASCII 码&lt;/h3&gt;
&lt;p&gt;美国信息交换标准代码，用 7 位二进制代码（共 128 个）来表示信息，广泛应用于计算机和通信领域中；&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/coding/ascii.jpg&#34; alt=&#34;ascii&#34; /&gt;&lt;/p&gt;
&lt;p&gt;在线查询：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cucnVub29iLmNvbS93M2Nub3RlL2FzY2lpLmh0bWw=&#34;&gt;菜鸟教程&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly90b29sLm9zY2hpbmEubmV0L2NvbW1vbnM/dHlwZT00&#34;&gt;OSchina&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;数制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数制&#34;&gt;#&lt;/a&gt; 数制&lt;/h1&gt;
&lt;h2 id=&#34;数制的概念&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数制的概念&#34;&gt;#&lt;/a&gt; 数制的概念&lt;/h2&gt;
&lt;p&gt;数制 (numerical system)，又称 “计数制”，指用一组固定的符号和统一的规则来表示数值的方法；&lt;/p&gt;
&lt;p&gt;数制关注的内容：每一位的构成（使用什么符号即数码）和进位的规则；&lt;/p&gt;
&lt;p&gt;基本概念：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;基数 —— 使用的数码的个数，即每一位最多能用多少个符号来表示；基数是 N 则称为 N 进制， 即 “逢 N 进一”&lt;/li&gt;
&lt;li&gt;权 —— 每一位的 1 代表的大小；&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;常用数制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常用数制&#34;&gt;#&lt;/a&gt; 常用数制&lt;/h2&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/de/bool-algebre/%E5%B8%B8%E7%94%A8%E6%95%B0%E5%88%B6.png&#34; alt=&#34;常用数制&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;不同进制的转换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#不同进制的转换&#34;&gt;#&lt;/a&gt; 不同进制的转换&lt;/h2&gt;
&lt;h3 id=&#34;其他进制-十进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#其他进制-十进制&#34;&gt;#&lt;/a&gt; 其他进制 -&amp;gt; 十进制&lt;/h3&gt;
&lt;p&gt;只需要按照 &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;D&lt;/mi&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mo&gt;∑&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;msup&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;D=\sum k_i N^i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;D&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1.074674em;vertical-align:-0.25001em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mop op-symbol small-op&#34; style=&#34;position:relative;top:-0.0000050000000000050004em;&#34;&gt;∑&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.16666666666666666em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03148em;&#34;&gt;k&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03148em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.824664em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 展开即可；&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msub&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;k_i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.84444em;vertical-align:-0.15em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03148em;&#34;&gt;k&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.31166399999999994em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-left:-0.03148em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 为第 i 位的系数&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;N^i&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.824664em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.824664em;&#34;&gt;&lt;span style=&#34;top:-3.063em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;i&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 为第 i 位的权&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;N&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.68333em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; 为基数&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;十进制-二进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#十进制-二进制&#34;&gt;#&lt;/a&gt; 十进制 -&amp;gt; 二进制&lt;/h3&gt;
&lt;h4 id=&#34;整数部分&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#整数部分&#34;&gt;#&lt;/a&gt; 整数部分&lt;/h4&gt;
&lt;p&gt;反复除 2 取余数，&lt;strong&gt;倒排&lt;/strong&gt;（从右向左排列）（从低位到高位排列）；&lt;/p&gt;
&lt;h4 id=&#34;小数部分&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#小数部分&#34;&gt;#&lt;/a&gt; 小数部分&lt;/h4&gt;
&lt;p&gt;反复乘 2 取整数部分，&lt;strong&gt;正排&lt;/strong&gt;（从左向右排列）（从高位到低位排列）；&lt;/p&gt;
&lt;h3 id=&#34;二进制-十六进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#二进制-十六进制&#34;&gt;#&lt;/a&gt; 二进制 -&amp;gt; 十六进制&lt;/h3&gt;
&lt;h4 id=&#34;整数部分-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#整数部分-2&#34;&gt;#&lt;/a&gt; 整数部分&lt;/h4&gt;
&lt;p&gt;从右向左（从低位到高位）每四个划为一组（不够的在左边补 0 ），&lt;/p&gt;
&lt;h4 id=&#34;小数部分-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#小数部分-2&#34;&gt;#&lt;/a&gt; 小数部分&lt;/h4&gt;
&lt;p&gt;从左向右（从高位到低位）每四个划为一组（不够的在右边补 0 ）；&lt;/p&gt;
&lt;h3 id=&#34;二进制-八进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#二进制-八进制&#34;&gt;#&lt;/a&gt; 二进制 -&amp;gt; 八进制&lt;/h3&gt;
&lt;h4 id=&#34;整数部分-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#整数部分-3&#34;&gt;#&lt;/a&gt; 整数部分&lt;/h4&gt;
&lt;p&gt;从右向左（从低位到高位）每三个划为一组（不够的在左边补 0 ），&lt;/p&gt;
&lt;h4 id=&#34;小数部分-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#小数部分-3&#34;&gt;#&lt;/a&gt; 小数部分&lt;/h4&gt;
&lt;p&gt;从左向右（从高位到低位）每三个划为一组（不够的在右边补 0 ）；&lt;/p&gt;
&lt;h3 id=&#34;十六进制-二进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#十六进制-二进制&#34;&gt;#&lt;/a&gt; 十六进制 -&amp;gt; 二进制&lt;/h3&gt;
&lt;p&gt;将每一位用对应的四位二进制数代替即可&lt;/p&gt;
&lt;h3 id=&#34;八进制-二进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#八进制-二进制&#34;&gt;#&lt;/a&gt; 八进制 -&amp;gt; 二进制&lt;/h3&gt;
&lt;p&gt;将每一位用对应的三位二进制数代替即可&lt;/p&gt;
&lt;h3 id=&#34;十进制-八进制-十六进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#十进制-八进制-十六进制&#34;&gt;#&lt;/a&gt; 十进制 -&amp;gt; 八进制、十六进制&lt;/h3&gt;
&lt;p&gt;先转换为二进制，再将二进制转换为八进制、十六进制&lt;/p&gt;
&lt;h3 id=&#34;八进制-十六进制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#八进制-十六进制&#34;&gt;#&lt;/a&gt; 八进制 &amp;lt;-&amp;gt; 十六进制&lt;/h3&gt;
&lt;p&gt;先转换为二进制，再将二进制转换为目标进制&lt;/p&gt;
&lt;h2 id=&#34;二进制算术运算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#二进制算术运算&#34;&gt;#&lt;/a&gt; 二进制算术运算&lt;/h2&gt;
&lt;h3 id=&#34;特点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#特点&#34;&gt;#&lt;/a&gt; 特点&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;和十进制算数运算的规则基本相同，区别在于 “逢二进一”&lt;/li&gt;
&lt;li&gt;乘法和除法可以转化为移位操作与加减操作&lt;/li&gt;
&lt;li&gt;通过补码运算（即将引入的概念），可以将减法运算转换为加法运算；&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;因此，数字电路普遍采用二进制进行算术运算&lt;/p&gt;
&lt;h3 id=&#34;有符号-二进制数&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#有符号-二进制数&#34;&gt;#&lt;/a&gt; (有符号) 二进制数&lt;/h3&gt;
&lt;p&gt;在前面增加一个符号位，0 表示正数，1 表示负数；&lt;/p&gt;
&lt;p&gt;一个二进制数的最高位是符号位，符号位的 0 / 1 不代表大小，只是代表正负&lt;/p&gt;
&lt;h3 id=&#34;原码-反码-补码&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#原码-反码-补码&#34;&gt;#&lt;/a&gt; 原码、反码、补码&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;正数（符号位为 0）—— 原码 = 反码 = 补码；&lt;/li&gt;
&lt;li&gt;负数（符号位为 1）—— 反码为所有数字位取反，补码等于反码加 1；&lt;/li&gt;
&lt;/ul&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;补码的补码即为原码&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;关于原码、反码、补码的易错点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;反码取反是指对数字位取反，不改变符号位！
&lt;ul&gt;
&lt;li&gt;例如 -7 即 1111 的反码是 1000，不是 0000 ！&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;补码是不对称的，例如补码为 1000 代表 - 8 ，而不代表 - 0 ！ 即同样位数的二进制补码，负数会比正数 “多一个”；&lt;/li&gt;
&lt;li&gt;补码的 “加 1” 指的是在最低位加 1 的二进制加法运算，不是指数值 1，即如果含有小数部分，1 是加在整体的最右边；&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;利用二进制补码运算求解带符号数的加法运算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#利用二进制补码运算求解带符号数的加法运算&#34;&gt;#&lt;/a&gt; 利用二进制补码运算求解带符号数的加法运算&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;分析需要使用多少个数字位；（培养思维习惯！不能忽略！）&lt;/li&gt;
&lt;li&gt;用带符号位的二进制数表示，求解每个二进制数的补码；&lt;/li&gt;
&lt;li&gt;对补码进行加法运算，再对结果求补码，即为最终结果；&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;注意最后一步，对补码进行加法运算时，数字位最高位产生的进位要进到符号位上去！（教材中描述的 “舍弃产生的进位” 指的是舍弃符号位产生的进位）&lt;/p&gt;
&lt;/div&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;人工智能的概念&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#人工智能的概念&#34;&gt;#&lt;/a&gt; 人工智能的概念&lt;/h1&gt;
&lt;p&gt;人工智能（Artificial Intelligence - AI）：研究如何通过计算机技术实现一个智能体，让智能体完成类似于人类智能的行为。&lt;/p&gt;
&lt;h2 id=&#34;智能体-agent&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智能体-agent&#34;&gt;#&lt;/a&gt; 智能体 Agent&lt;/h2&gt;
&lt;p&gt;完成智能行为的主体，是物理或抽象实体，可以感知世界并对世界施加作用。&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;大模型智能体 LLM Agent&lt;/p&gt;
&lt;p&gt;在近几年随 ChatGPT 兴起的新概念&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;智能体的两大目标&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智能体的两大目标&#34;&gt;#&lt;/a&gt; 智能体的两大目标&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;能否使智能体像人一样&lt;strong&gt;思考&lt;/strong&gt;、理性地思考？&lt;/li&gt;
&lt;li&gt;能否使智能体像人一样&lt;strong&gt;行动&lt;/strong&gt;、理性地行动？&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;智能体可否像人一样思考&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智能体可否像人一样思考&#34;&gt;#&lt;/a&gt; 智能体可否像人一样思考&lt;/h4&gt;
&lt;p&gt;首先，需要测量人如何思考的方法：内省、心理实验、 脑成像。&lt;/p&gt;
&lt;h5 id=&#34;认知科学&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#认知科学&#34;&gt;#&lt;/a&gt; 认知科学&lt;/h5&gt;
&lt;p&gt;交叉学科，融合人工智能的计算机模型和心理学实验技术，试图构建一种精确可测试的人类思维理论。&lt;/p&gt;
&lt;h5 id=&#34;认知神经科学&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#认知神经科学&#34;&gt;#&lt;/a&gt; 认知神经科学&lt;/h5&gt;
&lt;p&gt;交叉学科，以认知科学的理论以及神经心理学、神经科学及计算机模型的实验证据为基础。&lt;/p&gt;
&lt;h4 id=&#34;智能体如何像人一样行动&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智能体如何像人一样行动&#34;&gt;#&lt;/a&gt; 智能体如何像人一样行动&lt;/h4&gt;
&lt;h5 id=&#34;图林测试&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#图林测试&#34;&gt;#&lt;/a&gt; 图林测试&lt;/h5&gt;
&lt;p&gt;1950 年，英国数学家图灵 (Alan Turing) 提出了一个测试方法来确定一个机器是否具有人类智能。&lt;/p&gt;
&lt;h6 id=&#34;图林测试内容&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#图林测试内容&#34;&gt;#&lt;/a&gt; 图林测试内容&lt;/h6&gt;
&lt;ul&gt;
&lt;li&gt;两个人对机器进行测试：一人扮演提问者，另外一人作为被测者。&lt;/li&gt;
&lt;li&gt;这两人与机器分别处在三个不同的房间，提问者通过打印问题和接受打印问题来与被测者和被测机器进行通迅。提问者可以向被测机器和被测者提问，但他只知道接受提问的是 A 或 B，而并不知道他是人还是机器。&lt;/li&gt;
&lt;li&gt;若超过 30% 的测试者不能确定出被测试者是人还是机器，那么这台机器就通过了测试，并被认为具有人类智能。&lt;/li&gt;
&lt;/ul&gt;
&lt;h6 id=&#34;图灵提出了ai的几大元素&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#图灵提出了ai的几大元素&#34;&gt;#&lt;/a&gt; 图灵提出了 AI 的几大元素&lt;/h6&gt;
&lt;ul&gt;
&lt;li&gt;知识&lt;/li&gt;
&lt;li&gt;推理&lt;/li&gt;
&lt;li&gt;语言&lt;/li&gt;
&lt;li&gt;理解&lt;/li&gt;
&lt;li&gt;学习&lt;/li&gt;
&lt;/ul&gt;
&lt;h6 id=&#34;图灵测试存在的问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#图灵测试存在的问题&#34;&gt;#&lt;/a&gt; 图灵测试存在的问题&lt;/h6&gt;
&lt;ul&gt;
&lt;li&gt;图灵测试不可重复&lt;/li&gt;
&lt;li&gt;无法数学分析&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;三大主流学派&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三大主流学派&#34;&gt;#&lt;/a&gt; 三大主流学派&lt;/h2&gt;
&lt;h3 id=&#34;逻辑学派&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#逻辑学派&#34;&gt;#&lt;/a&gt; 逻辑学派&lt;/h3&gt;
&lt;p&gt;符号主义 / 功能主义方法，模拟大脑逻辑思维&lt;strong&gt;功能&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;原理主要为物理符号系统 (即符号操作系统) 假设和有限合理性原理。&lt;/p&gt;
&lt;h3 id=&#34;仿生学派&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#仿生学派&#34;&gt;#&lt;/a&gt; 仿生学派&lt;/h3&gt;
&lt;p&gt;联结主义 / 结构主义方法，模拟大脑&lt;strong&gt;结构&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;原理主要为神经网络及神经网络间的连接机制与学习算法&lt;/p&gt;
&lt;h3 id=&#34;控制论学派&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#控制论学派&#34;&gt;#&lt;/a&gt; 控制论学派&lt;/h3&gt;
&lt;p&gt;行为主义 / 进化主义方法，模拟智能系统&lt;strong&gt;行为&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;原理为控制论及感知 — 动作型控制系统&lt;/p&gt;
&lt;h2 id=&#34;理论基础&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#理论基础&#34;&gt;#&lt;/a&gt; 理论基础&lt;/h2&gt;
&lt;h3 id=&#34;物理符号系统的假设&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#物理符号系统的假设&#34;&gt;#&lt;/a&gt; 物理符号系统的假设&lt;/h3&gt;
&lt;p&gt;一个完善的符号系统应具有下列 6 种功能&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;输入 (input) 符号&lt;/li&gt;
&lt;li&gt;输出 (output) 符号&lt;/li&gt;
&lt;li&gt;存储 (store) 符号&lt;/li&gt;
&lt;li&gt;复制 (copy) 符号&lt;/li&gt;
&lt;li&gt;建立符号结构：通过找出各符号间的关系，在符号系统中形成符号结构&lt;/li&gt;
&lt;li&gt;条件性迁移 (conditi onal transfer) : 根据已有符号，继续完成活动过程&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;任何一个系统，如果它能够表现出智能，那么它就必定能够执行上述 6 种功能。反之，任何系统如果具有这 6 种功能，那么它就能够表现出智能；这种智能指的是人类所具有的那种智能。&lt;/p&gt;
&lt;p&gt;物理符号系统的假设伴随 3 个推论，或称为附带条件&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;既然人具有智能，那么他就 一定是 一个物理符号系统。人之所以能够表现出智能，就是基 于他的信息处理过程&lt;/li&gt;
&lt;li&gt;既 然 计 算 机 是 一个 物 理 符 号 系 统 ，它 就 一定 能 够 表 现 出 智 能 。这 是 人 工 智能的基本条件。&lt;/li&gt;
&lt;li&gt;既然人是 一个物理符号系统，计算机也是 一个物理符号系统，那么就能够 用计算机模拟人的活动&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;人工智能的内涵&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#人工智能的内涵&#34;&gt;#&lt;/a&gt; 人工智能的内涵&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;搜索&lt;/li&gt;
&lt;li&gt;知识&lt;/li&gt;
&lt;li&gt;推理&lt;/li&gt;
&lt;li&gt;归纳&lt;/li&gt;
&lt;li&gt;演绎&lt;/li&gt;
&lt;li&gt;...&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;强弱-人工智能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#强弱-人工智能&#34;&gt;#&lt;/a&gt; 强 / 弱 人工智能&lt;/h2&gt;
&lt;h3 id=&#34;强人工智能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#强人工智能&#34;&gt;#&lt;/a&gt; 强人工智能&lt;/h3&gt;
&lt;p&gt;一个机器和人的思考行为都完全一样&lt;/p&gt;
&lt;h3 id=&#34;弱人工智能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#弱人工智能&#34;&gt;#&lt;/a&gt; 弱人工智能&lt;/h3&gt;
&lt;p&gt;只能表面上执行看上去的智能行为&lt;/p&gt;
&lt;h2 id=&#34;泛狭义-人工智能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#泛狭义-人工智能&#34;&gt;#&lt;/a&gt; 泛 / 狭义 人工智能&lt;/h2&gt;
&lt;h3 id=&#34;泛人工智能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#泛人工智能&#34;&gt;#&lt;/a&gt; 泛人工智能&lt;/h3&gt;
&lt;p&gt;智能体拥有在任何问题上应用智能的能力&lt;/p&gt;
&lt;h3 id=&#34;狭义人工智能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#狭义人工智能&#34;&gt;#&lt;/a&gt; 狭义人工智能&lt;/h3&gt;
&lt;p&gt;只能完成一项具体任务的人工智能&lt;/p&gt;
&lt;h1 id=&#34;人工智能的发展历史&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#人工智能的发展历史&#34;&gt;#&lt;/a&gt; 人工智能的发展历史&lt;/h1&gt;
&lt;h2 id=&#34;不同阶段&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#不同阶段&#34;&gt;#&lt;/a&gt; 不同阶段&lt;/h2&gt;
&lt;h3 id=&#34;1950-1970&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1950-1970&#34;&gt;#&lt;/a&gt; 1950-1970&lt;/h3&gt;
&lt;p&gt;早期爆发阶段，巨大期望&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;1952：Samuel 写了一个能学习的五子棋程序&lt;/li&gt;
&lt;li&gt;1955：Newell 和 Simon 写了一个推理的程序&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;1970-1990&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1970-1990&#34;&gt;#&lt;/a&gt; 1970-1990&lt;/h3&gt;
&lt;p&gt;知识就是力量，知识工程&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;1980-1988：专家系统工业爆发&lt;/li&gt;
&lt;li&gt;1988-1993： 日本第五代计算机系统项目失败&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;1990-&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1990-&#34;&gt;#&lt;/a&gt; 1990-&lt;/h3&gt;
&lt;p&gt;机器学习兴起，人工智能的春天&lt;/p&gt;
&lt;h3 id=&#34;2010-&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2010-&#34;&gt;#&lt;/a&gt; 2010-&lt;/h3&gt;
&lt;p&gt;深度学习获得工业投资和应用&lt;/p&gt;
&lt;h2 id=&#34;三次大跃进&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三次大跃进&#34;&gt;#&lt;/a&gt; 三次大跃进&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;智能系统代替人完成部分逻辑推理工作，如机器 定理证明和专家系统&lt;/li&gt;
&lt;li&gt;智能系统能够和环境交互，从运行的环境中获取信息，代替人完成包括不定性在内的部分思维 工作，通过自身的动作，对环境施加影响，并适应环境的变化，如智能机器人&lt;/li&gt;
&lt;li&gt;智 能 系 统 具 有 人 类 的 认 知 和 思 维 能 力 ，能 够 发 现 新 的 知 识 ，完 成 面 临 的 任 务 ，如 基 于 数 据 挖 掘 的 系 统&lt;/li&gt;
&lt;/ol&gt;
&lt;h1 id=&#34;人工智能研究课题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#人工智能研究课题&#34;&gt;#&lt;/a&gt; 人工智能研究课题&lt;/h1&gt;
&lt;h2 id=&#34;智-能-感-知&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智-能-感-知&#34;&gt;#&lt;/a&gt; 智 能 感 知&lt;/h2&gt;
&lt;h3 id=&#34;模式识别&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#模式识别&#34;&gt;#&lt;/a&gt; 模式识别&lt;/h3&gt;
&lt;h3 id=&#34;计算机视觉&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算机视觉&#34;&gt;#&lt;/a&gt; 计算机视觉&lt;/h3&gt;
&lt;h3 id=&#34;自然语言处理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#自然语言处理&#34;&gt;#&lt;/a&gt; 自然语言处理&lt;/h3&gt;
&lt;h2 id=&#34;智-能-推-理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智-能-推-理&#34;&gt;#&lt;/a&gt; 智 能 推 理&lt;/h2&gt;
&lt;h3 id=&#34;搜索技术&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#搜索技术&#34;&gt;#&lt;/a&gt; 搜索技术&lt;/h3&gt;
&lt;h3 id=&#34;问题求解&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#问题求解&#34;&gt;#&lt;/a&gt; 问题求解&lt;/h3&gt;
&lt;h3 id=&#34;定理证明&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#定理证明&#34;&gt;#&lt;/a&gt; 定理证明&lt;/h3&gt;
&lt;h3 id=&#34;专家系统和知识库&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#专家系统和知识库&#34;&gt;#&lt;/a&gt; 专家系统和知识库&lt;/h3&gt;
&lt;h3 id=&#34;大数据知识工程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#大数据知识工程&#34;&gt;#&lt;/a&gt; 大数据知识工程&lt;/h3&gt;
&lt;h2 id=&#34;智-能-学-习&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智-能-学-习&#34;&gt;#&lt;/a&gt; 智 能 学 习&lt;/h2&gt;
&lt;h3 id=&#34;记忆与联想&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#记忆与联想&#34;&gt;#&lt;/a&gt; 记忆与联想&lt;/h3&gt;
&lt;h3 id=&#34;神经网络&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#神经网络&#34;&gt;#&lt;/a&gt; 神经网络&lt;/h3&gt;
&lt;h3 id=&#34;深度学习-迁移学习&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#深度学习-迁移学习&#34;&gt;#&lt;/a&gt; 深度学习、迁移学习&lt;/h3&gt;
&lt;h3 id=&#34;计算智能与进化计算&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算智能与进化计算&#34;&gt;#&lt;/a&gt; 计算智能与进化计算&lt;/h3&gt;
&lt;h3 id=&#34;遗传算法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#遗传算法&#34;&gt;#&lt;/a&gt; 遗传算法&lt;/h3&gt;
&lt;h3 id=&#34;数据挖掘与知识发现&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据挖掘与知识发现&#34;&gt;#&lt;/a&gt; 数据挖掘与知识发现&lt;/h3&gt;
&lt;h2 id=&#34;智-能-行-动&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智-能-行-动&#34;&gt;#&lt;/a&gt; 智 能 行 动&lt;/h2&gt;
&lt;h3 id=&#34;智能检索&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智能检索&#34;&gt;#&lt;/a&gt; 智能检索&lt;/h3&gt;
&lt;h3 id=&#34;智能调度与指挥&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智能调度与指挥&#34;&gt;#&lt;/a&gt; 智能调度与指挥&lt;/h3&gt;
&lt;h3 id=&#34;智能控制&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智能控制&#34;&gt;#&lt;/a&gt; 智能控制&lt;/h3&gt;
&lt;h3 id=&#34;人机对话系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#人机对话系统&#34;&gt;#&lt;/a&gt; 人机对话系统&lt;/h3&gt;
&lt;h3 id=&#34;智能机器人&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#智能机器人&#34;&gt;#&lt;/a&gt; 智能机器人&lt;/h3&gt;
&lt;h3 id=&#34;分布式人工智能与agent&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分布式人工智能与agent&#34;&gt;#&lt;/a&gt; 分布式人工智能与 Agent&lt;/h3&gt;
&lt;h3 id=&#34;游戏&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#游戏&#34;&gt;#&lt;/a&gt; 游戏&lt;/h3&gt;
&lt;h3 id=&#34;人机智能融合&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#人机智能融合&#34;&gt;#&lt;/a&gt; 人机智能融合&lt;/h3&gt;
&lt;h1 id=&#34;人工智能实例&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#人工智能实例&#34;&gt;#&lt;/a&gt; 人工智能实例&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;专家系统：在专门的领域（医疗、探矿、财务等领域）内的咨询服务系统&lt;/li&gt;
&lt;li&gt;自然语言处理：在有限范围内的问题回答系统。&lt;/li&gt;
&lt;li&gt;程序验证系统：通过定理证明途径验证程序的正确性。&lt;/li&gt;
&lt;li&gt;智能机器人：通过计算机视觉和智能控制完成具体行动任务&lt;/li&gt;
&lt;/ul&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;参考资料&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#参考资料&#34;&gt;#&lt;/a&gt; 参考资料&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jb3Vyc2UucnM=&#34;&gt;Rust 语言圣经 (自称)&lt;/span&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ydXN0eS5jb3Vyc2UucnM=&#34;&gt;锈书&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cucnVzdC1sYW5nLm9yZw==&#34;&gt;官网&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;环境配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#环境配置&#34;&gt;#&lt;/a&gt; 环境配置&lt;/h1&gt;
&lt;p&gt;更新 Rust&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;span&gt;bash&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rustup update&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;卸载 Rust&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;span&gt;bash&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rustup self uninstall&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;查看版本&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;span&gt;h bash&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rustc &lt;span class=&#34;token parameter variable&#34;&gt;--version&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;## 显示格式&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rustc.x.y.z&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;commit hash&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;commit date&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;安装 Rust 同时还会安装文档，查看本地文档&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;span&gt;bash&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rustup doc&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;rust-工具&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rust-工具&#34;&gt;#&lt;/a&gt; Rust 工具&lt;/h1&gt;
&lt;h1 id=&#34;编译器&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#编译器&#34;&gt;#&lt;/a&gt; 编译器&lt;/h1&gt;
&lt;h2 id=&#34;rustc&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rustc&#34;&gt;#&lt;/a&gt;  &lt;code&gt;rustc&lt;/code&gt;&lt;/h2&gt;
&lt;p&gt;只适合单文件编译&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;span&gt;shell&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;rustc xxx.rs &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt;output&lt;span class=&#34;token operator&#34;&gt;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;cargo&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cargo&#34;&gt;#&lt;/a&gt;  &lt;code&gt;cargo&lt;/code&gt;&lt;/h2&gt;
&lt;p&gt;Cargo 是 Rust 的构建系统和包管理工具，适用于较大型项目编译、链接&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;构建代码&lt;/li&gt;
&lt;li&gt;下载依赖的库&lt;/li&gt;
&lt;li&gt;构建这些库&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;创建项目，会创建一个新目录  &lt;code&gt;project&lt;/code&gt;  并且初始化一个 git 项目&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;span&gt;shell&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cargo&lt;/span&gt; new project&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;创建好的项目结构&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;span&gt;shell&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token builtin class-name&#34;&gt;.&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;├── .git&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;├── .gitignore&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;├── Cargo.toml&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;└── src&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    └── main.rs&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;检查代码能否通过编译，并不会编译项目，很常用&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;span&gt;shell&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cargo&lt;/span&gt; check&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;构建项目&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;span&gt;shell&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cargo&lt;/span&gt; build           &lt;span class=&#34;token comment&#34;&gt;# 默认为调试模式即 --debug&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cargo&lt;/span&gt; build &lt;span class=&#34;token parameter variable&#34;&gt;--debug&lt;/span&gt;   &lt;span class=&#34;token comment&#34;&gt;# 同上&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cargo&lt;/span&gt; build &lt;span class=&#34;token parameter variable&#34;&gt;--release&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 发布模式，编译出的程序性能更高&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;运行项目&lt;/p&gt;
&lt;figure class=&#34;highlight shell&#34;&gt;&lt;figcaption data-lang=&#34;Bash&#34;&gt;&lt;span&gt;shell&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cargo&lt;/span&gt; run           &lt;span class=&#34;token comment&#34;&gt;# 默认为调试模式即 --debug&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cargo&lt;/span&gt; run &lt;span class=&#34;token parameter variable&#34;&gt;--debug&lt;/span&gt;   &lt;span class=&#34;token comment&#34;&gt;# 同上&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;cargo&lt;/span&gt; run &lt;span class=&#34;token parameter variable&#34;&gt;--release&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 发布模式，编译出的程序性能更高&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;安装依赖库换源&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#安装依赖库换源&#34;&gt;#&lt;/a&gt; 安装依赖库换源&lt;/h3&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;目前  &lt;code&gt;cargo search&lt;/code&gt;  无法使用镜像&lt;/p&gt;
&lt;/div&gt;
&lt;ul&gt;
&lt;li&gt;字节镜像源&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9yc3Byb3h5LmNu&#34;&gt;参考&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;华科镜像源&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9taXJyb3JzLnVzdGMuZWR1LmNuL2hlbHAvY3JhdGVzLmlvLWluZGV4Lmh0bWw=&#34;&gt;参考&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;方法一&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法一&#34;&gt;#&lt;/a&gt; 方法一&lt;/h4&gt;
&lt;p&gt;在  &lt;code&gt;$HOME/.cargo/config.toml&lt;/code&gt;  文件 (没有则创建一个) 添加如下内容：&lt;/p&gt;
&lt;figure class=&#34;highlight toml&#34;&gt;&lt;figcaption data-lang=&#34;TOML&#34;&gt;&lt;span&gt;l toml&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 华科镜像源&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;registries&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;ustc&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token key property&#34;&gt;index&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;https://mirrors.ustc.edu.cn/crates.io-index/&#34;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;# 或者&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;registries.ustc&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;index&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;https://mirrors.ustc.edu.cn/crates.io-index/&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;或者稀疏索引的方式，要求 cargo &amp;gt;= 1.68 ：&lt;/p&gt;
&lt;figure class=&#34;highlight toml&#34;&gt;&lt;figcaption data-lang=&#34;TOML&#34;&gt;&lt;span&gt;toml&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;source.ustc-sparse&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;registry&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;sparse+https://mirrors.ustc.edu.cn/crates.io-index/&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;同时需要在项目  &lt;code&gt;cargo.toml&lt;/code&gt;  使用注册方式引入依赖库：&lt;/p&gt;
&lt;figure class=&#34;highlight toml&#34;&gt;&lt;figcaption data-lang=&#34;TOML&#34;&gt;&lt;span&gt;toml&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;dependencies&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&amp;lt;要引入的包&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token key property&#34;&gt;registry&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;ustc&#34;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&amp;lt;要引入的包&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token key property&#34;&gt;registry&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;rsproxy&#34;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;方法二&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#方法二&#34;&gt;#&lt;/a&gt; 方法二&lt;/h4&gt;
&lt;p&gt;不需要对项目  &lt;code&gt;cargo.toml&lt;/code&gt;  添加配置，只需要  &lt;code&gt;$HOME/.cargo/config.toml&lt;/code&gt;  文件 (没有则创建一个) 添加如下内容：&lt;/p&gt;
&lt;figure class=&#34;highlight toml&#34;&gt;&lt;figcaption data-lang=&#34;TOML&#34;&gt;&lt;span&gt;toml&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;source.crates-io&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;replace-with&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;rsproxy&#39;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 字节跳动镜像源&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;source.rsproxy&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;registry&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;https://rsproxy.cn/crates.io-index&#34;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;# 镜像源 url&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;稀疏索引，要求 cargo &amp;gt;= 1.68 ：&lt;/p&gt;
&lt;figure class=&#34;highlight toml&#34;&gt;&lt;figcaption data-lang=&#34;TOML&#34;&gt;&lt;span&gt;toml&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;source.rsproxy-sparse&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;registry&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;sparse+https://rsproxy.cn/index/&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;registries.rsproxy&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;index&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;https://rsproxy.cn/crates.io-index&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;net&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;git-fetch-with-cli&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;项目结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#项目结构&#34;&gt;#&lt;/a&gt; 项目结构&lt;/h1&gt;
&lt;h2 id=&#34;项目结构要求&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#项目结构要求&#34;&gt;#&lt;/a&gt; 项目结构要求&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;Cargo.toml 在项目顶层下&lt;/li&gt;
&lt;li&gt;源代码都应该在 src 目录下&lt;/li&gt;
&lt;li&gt;顶层目录可以放置：README、许可信息、配置文件和其它与程序源码无关的文件&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;如果创建项目时没有使用 cargo，也可以把项目转化为使用 cargo：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;把源代码文件移动到 src 下&lt;/li&gt;
&lt;li&gt;创建 Cargo.toml 并填写相应的配置&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;cargotoml&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cargotoml&#34;&gt;#&lt;/a&gt;  &lt;code&gt;Cargo.toml&lt;/code&gt;&lt;/h2&gt;
&lt;h3 id=&#34;package&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#package&#34;&gt;#&lt;/a&gt;  &lt;code&gt;[package]&lt;/code&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;name&lt;/li&gt;
&lt;li&gt;version&lt;/li&gt;
&lt;li&gt;authors&lt;/li&gt;
&lt;li&gt;edition&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;dependencies&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#dependencies&#34;&gt;#&lt;/a&gt;  &lt;code&gt;[dependencies]&lt;/code&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;crate 包&lt;/li&gt;
&lt;li&gt;...&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;三种描述：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;基于 Rust 官方仓库  &lt;code&gt;crates.io&lt;/code&gt; ，通过版本说明来描述&lt;/li&gt;
&lt;li&gt;基于项目源代码的 git 仓库地址，通过 URL 来描述&lt;/li&gt;
&lt;li&gt;基于本地项目的绝对路径或者相对路径，通过类 Unix 模式的路径来描述&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;eg :&lt;/p&gt;
&lt;figure class=&#34;highlight toml&#34;&gt;&lt;figcaption data-lang=&#34;TOML&#34;&gt;&lt;span&gt;l toml&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token table class-name&#34;&gt;dependencies&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;rand&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;0.3&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;hammer&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token key property&#34;&gt;version&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;0.5.0&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;color&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token key property&#34;&gt;git&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;https://github.com/bjz/color-rs&#34;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token key property&#34;&gt;geometry&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token key property&#34;&gt;path&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;crates/geometry&#34;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;变量和常量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#变量和常量&#34;&gt;#&lt;/a&gt; 变量和常量&lt;/h1&gt;
&lt;h2 id=&#34;变量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#变量&#34;&gt;#&lt;/a&gt; 变量&lt;/h2&gt;
&lt;h3 id=&#34;let变量绑定-binding&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#let变量绑定-binding&#34;&gt;#&lt;/a&gt;  &lt;code&gt;let&lt;/code&gt;  变量绑定 (binding)&lt;/h3&gt;
&lt;p&gt;rust 中  &lt;code&gt;let&lt;/code&gt;  表达式的类似其他语言赋值的作用，实际上不是赋值，而叫做 &lt;strong&gt;绑定&lt;/strong&gt;，这与 rust &lt;strong&gt;所有权&lt;/strong&gt; 这一核心概念有关&lt;/p&gt;
&lt;p&gt;默认绑定变量类型为  &lt;code&gt;immutable&lt;/code&gt;  不可变的，需要可变则须加上  &lt;code&gt;mut&lt;/code&gt;  显式声明&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 使用 let 来声明变量，进行绑定，a 是不可变的&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 此处没有指定 a 的类型，编译器会默认根据 a 的值为 a 推断类型：i32，有符号 32 位整数&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 语句的末尾必须以分号结尾&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 主动指定 b 的类型为 i32&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;20&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 这里有两点值得注意：&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 1. 可以在数值中带上类型：30i32 表示数值是 30，类型是 i32&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 2. c 是可变的，mut 是 mutable 的缩写&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;mut&lt;/span&gt; c &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;30i32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 还能在数值和类型中间添加一个下划线，让可读性更好&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; d &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;30_i32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 跟其它语言一样，可以使用一个函数的返回值来作为另一个函数的参数&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; e &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;add&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;c&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; d&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;_编译器忽略未使用变量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#_编译器忽略未使用变量&#34;&gt;#&lt;/a&gt;  &lt;code&gt;_&lt;/code&gt; 编译器忽略未使用变量&lt;/h3&gt;
&lt;p&gt;告诉编译器不要警告未使用的变量，为此可以用下划线作为变量名的开头&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rsut&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; _a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;let变量解构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#let变量解构&#34;&gt;#&lt;/a&gt;  &lt;code&gt;let&lt;/code&gt;  变量解构&lt;/h3&gt;
&lt;p&gt;从一个复杂的变量中匹配出部分内容&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;mut&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;bool&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;bool&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;false&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;//a = true, 不可变；b = false，可变&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;println!&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;a = &amp;#123;:?&amp;#125;, b = &amp;#123;:?&amp;#125;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;b &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;assert_eq!&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;解构式赋值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#解构式赋值&#34;&gt;#&lt;/a&gt; 解构式赋值&lt;/h3&gt;
&lt;p&gt;在 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9jb3Vyc2UucnMvYXBwZW5kaXgvcnVzdC12ZXJzaW9ucy8xLjU5Lmh0bWw=&#34;&gt;Rust 1.59&lt;/span&gt; 版本后可以在赋值语句的左式中使用元组、切片和结构体模式，不需要  &lt;code&gt;let&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token type-definition class-name&#34;&gt;Struct&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    e&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;fn&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; c&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; d&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token comment&#34;&gt;//_ 代表匹配一个值，但是我们不关心具体的值是什么，因此没有使用一个变量名而是使用了 _&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;c&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; d&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; _&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token class-name&#34;&gt;Struct&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;..&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Struct&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token macro property&#34;&gt;assert_eq!&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; b&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; c&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; d&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; e&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;这种使用方式跟之前的  &lt;code&gt;let&lt;/code&gt;  保持了一致性，但是  &lt;code&gt;let&lt;/code&gt;  会重新绑定，而这里仅仅是对之前绑定的变量进行再赋值。&lt;/p&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;使用  &lt;code&gt;+=&lt;/code&gt;  的赋值语句还不支持解构式赋值&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;变量遮蔽-shadowing&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#变量遮蔽-shadowing&#34;&gt;#&lt;/a&gt; 变量遮蔽 (shadowing)&lt;/h3&gt;
&lt;p&gt;Rust 允许声明相同的变量名，在后面声明的变量会遮蔽掉前面声明的。&lt;/p&gt;
&lt;p&gt;变量遮蔽的用处在于，如果你在某个作用域内无需再使用之前的变量（在被遮蔽后，无法再访问到之前的同名变量），就可以重复的使用变量名字，而不用绞尽脑汁去想更多的名字。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;可以使用相同的名字声明新的变量，新的变量就会 shadow（隐藏）之前声明的同名变量&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;在后续的代码中这个变量名代表的就是新的变量&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;shadow 和把变量标记为 mut 是不一样的：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果不使用  &lt;code&gt;let&lt;/code&gt;  关键字，那么重新给非  &lt;code&gt;mut&lt;/code&gt;  的变量赋值会导致编译时错误&lt;/li&gt;
&lt;li&gt;而使用  &lt;code&gt;let&lt;/code&gt;  声明的同名新变量，也是不可变的&lt;/li&gt;
&lt;li&gt;使用  &lt;code&gt;let&lt;/code&gt;  声明的同名新变量，它的类型可以与之前不同&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;as变量类型转换&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#as变量类型转换&#34;&gt;#&lt;/a&gt;  &lt;code&gt;as&lt;/code&gt;  变量类型转换&lt;/h3&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;t rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; x&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; y&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;u32&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;u32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;Rust 有三种变量类型转换的方法：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;as&lt;/code&gt;  关键字&lt;/li&gt;
&lt;li&gt;&lt;code&gt;from&lt;/code&gt;  和  &lt;code&gt;into&lt;/code&gt;  这些  &lt;code&gt;trait&lt;/code&gt;  进行转换&lt;/li&gt;
&lt;li&gt;字符串类型可以使用  &lt;code&gt;parse&lt;/code&gt;  方法转换到数字类型&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;h2 id=&#34;常量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常量&#34;&gt;#&lt;/a&gt; 常量&lt;/h2&gt;
&lt;p&gt;常量也是绑定到一个常量名且不允许更改的值&lt;/p&gt;
&lt;h3 id=&#34;常量和变量之间的差异&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#常量和变量之间的差异&#34;&gt;#&lt;/a&gt; 常量和变量之间的差异&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;常量不允许使用  &lt;code&gt;mut&lt;/code&gt; 。&lt;strong&gt;常量不仅仅默认不可变，而且自始至终不可变&lt;/strong&gt;，因为常量在编译完成后，已经确定它的值。&lt;/li&gt;
&lt;li&gt;常量使用  &lt;code&gt;const&lt;/code&gt;  关键字而不是  &lt;code&gt;let&lt;/code&gt;  关键字来声明，并且值的&lt;strong&gt;类型必须标注&lt;/strong&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;rust-常量的命名约定&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#rust-常量的命名约定&#34;&gt;#&lt;/a&gt; Rust 常量的命名约定&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;全部字母都使用大写&lt;/li&gt;
&lt;li&gt;使用下划线分隔单词，另外对数字字面量可插入下划线以提高可读性&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;基本类型-标量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基本类型-标量&#34;&gt;#&lt;/a&gt; 基本类型 (标量)&lt;/h1&gt;
&lt;h2 id=&#34;原始类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#原始类型&#34;&gt;#&lt;/a&gt; 原始类型&lt;/h2&gt;
&lt;h3 id=&#34;整数类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#整数类型&#34;&gt;#&lt;/a&gt; 整数类型&lt;/h3&gt;
&lt;p&gt;类型定义的形式统一为： &lt;code&gt;有无符号 + 类型大小(位数)&lt;/code&gt;&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;长度&lt;/th&gt;
&lt;th&gt;有符号类型&lt;/th&gt;
&lt;th&gt;无符号类型&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;8 位&lt;/td&gt;
&lt;td&gt;&lt;code&gt;i8&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;u8&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;16 位&lt;/td&gt;
&lt;td&gt;&lt;code&gt;i16&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;u16&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;32 位&lt;/td&gt;
&lt;td&gt;&lt;code&gt;i32&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;u32&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;64 位&lt;/td&gt;
&lt;td&gt;&lt;code&gt;i64&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;u64&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;128 位&lt;/td&gt;
&lt;td&gt;&lt;code&gt;i128&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;u128&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;视架构而定&lt;/td&gt;
&lt;td&gt;&lt;code&gt;isize&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;&lt;code&gt;usize&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h4 id=&#34;isize-和-usize-类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#isize-和-usize-类型&#34;&gt;#&lt;/a&gt;  &lt;code&gt;isize&lt;/code&gt;  和  &lt;code&gt;usize&lt;/code&gt;  类型&lt;/h4&gt;
&lt;p&gt;&lt;code&gt;isize&lt;/code&gt;  和  &lt;code&gt;usize&lt;/code&gt;  类型的位数由程序运行的计算机的架构所决定：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果是 64 位计算机，那就是 64 位的&lt;/li&gt;
&lt;li&gt;如果是 32 位计算机，那就是 32 位的&lt;/li&gt;
&lt;li&gt;...&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;整数字面值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#整数字面值&#34;&gt;#&lt;/a&gt; 整数字面值&lt;/h4&gt;
&lt;p&gt;rust 有以下 5 种整数字面类型：&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;Number literals&lt;/th&gt;
&lt;th&gt;Example&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;Decimal&lt;/td&gt;
&lt;td&gt;98_222&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Hex&lt;/td&gt;
&lt;td&gt;0xff&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Octal&lt;/td&gt;
&lt;td&gt;0o77&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Binary&lt;/td&gt;
&lt;td&gt;0b1111_0000&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;Byte (u8 only)&lt;/td&gt;
&lt;td&gt;b&#39;A&#39;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;除了  &lt;code&gt;Byte&lt;/code&gt;  类型外，所有的数值字面值都允许使用类型后缀。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;例如  &lt;code&gt;57u8&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果不太清楚应该使用那种类型，可以使用 Rust 相应的默认类型&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;整数的默认类型就是  &lt;code&gt;i32&lt;/code&gt;  ，其速度整体上是较快的，即使是在 64 位操作系统中&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;整数溢出&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#整数溢出&#34;&gt;#&lt;/a&gt; 整数溢出&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;调试模式 (--debug) 下编译：Rust 会检查整数溢出，如果发生溢出，程序在运行时就会 panic&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;发布模式下（--release）编译：Rust 不会检查可能导致 panic 的整数溢出&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;如果溢出发生：Rust 会执行 “环绕” 操作：(取模)&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;例如： &lt;code&gt;u8&lt;/code&gt;  的范围是 0-255，如果把一个  &lt;code&gt;u8&lt;/code&gt;  变量的值设为 256，那么 Rust 会将 256 变成 0，257 变成 1 ⋯&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;但程序不会 panic&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;浮点类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#浮点类型&#34;&gt;#&lt;/a&gt; 浮点类型&lt;/h3&gt;
&lt;p&gt;Rust 有两种基础的浮点类型，也就是含有小数部分的类型：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;f32&lt;/code&gt; ，32 位，单精度&lt;/li&gt;
&lt;li&gt;&lt;code&gt;f64&lt;/code&gt; ，64 位，双精度&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Rust 的浮点类型使用了 IEEE-754 标准来表述&lt;/p&gt;
&lt;p&gt;&lt;mark&gt; &lt;code&gt;f64&lt;/code&gt;  是&lt;strong&gt;默认&lt;/strong&gt;类型，因为在现代 CPU 上  &lt;code&gt;f64&lt;/code&gt;  和  &lt;code&gt;f32&lt;/code&gt;  的速度差不多，而且精度更高。&lt;/mark&gt;&lt;/p&gt;
&lt;h3 id=&#34;布尔类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#布尔类型&#34;&gt;#&lt;/a&gt; 布尔类型&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Rust 的布尔类型也有两个值：
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;true&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;&lt;code&gt;false&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;占一个字节大小&lt;/li&gt;
&lt;li&gt;符号是  &lt;code&gt;bool&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;Rust 不允许其他类型直接当作布尔类型使用，和其他语言不太一样！&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;字符类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#字符类型&#34;&gt;#&lt;/a&gt; 字符类型&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;Rust 语言中 char 类型被用来描述语言中最基础的单个字符。&lt;/li&gt;
&lt;li&gt;字符类型的字面值使用单引号&lt;/li&gt;
&lt;li&gt;占用 &lt;strong&gt;4 字节&lt;/strong&gt;大小&lt;/li&gt;
&lt;li&gt;是 Unicode 标量值，可以表示比 ASCII 多得多的字符内容，包括：拼音、中日韩文、零长度空白字符、emoji 表情等。&lt;/li&gt;
&lt;/ul&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;Unicode 中并没有 “字符” 的概念，所以直觉上认为的字符也许与 Rust 中的概念并不相符&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;复合类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#复合类型&#34;&gt;#&lt;/a&gt; 复合类型&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;复合类型可以将多个值放在一个类型里。&lt;/li&gt;
&lt;li&gt;Rust 提供了两种基础的复合类型：元组（Tuple）、数组&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;tuple&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tuple&#34;&gt;#&lt;/a&gt;  &lt;code&gt;Tuple&lt;/code&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;Tuple&lt;/code&gt;  可以将多个类型的多个值放在一个类型里&lt;/li&gt;
&lt;li&gt;&lt;code&gt;Tuple&lt;/code&gt;  的长度是固定的：一旦声明就无法改变&lt;/li&gt;
&lt;li&gt;&lt;code&gt;Tuple&lt;/code&gt;  中的每个位置都对应一个类型， &lt;code&gt;Tuple&lt;/code&gt;  中各元素的类型不必相同&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;创建-tuple&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#创建-tuple&#34;&gt;#&lt;/a&gt; 创建  &lt;code&gt;Tuple&lt;/code&gt;&lt;/h4&gt;
&lt;p&gt;在小括号里，将值用逗号分开&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; tup&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;132&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;f64&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;48&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;500&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;6.4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;获取-tuple-的元素值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#获取-tuple-的元素值&#34;&gt;#&lt;/a&gt; 获取  &lt;code&gt;Tuple&lt;/code&gt;  的元素值&lt;/h4&gt;
&lt;p&gt;可以使用&lt;strong&gt;模式匹配&lt;/strong&gt;来解构（destructure）一个  &lt;code&gt;Tuple&lt;/code&gt;  来取元素的值&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; y&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; z&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; tup&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;访问-tuple-的元素&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#访问-tuple-的元素&#34;&gt;#&lt;/a&gt; 访问  &lt;code&gt;Tuple&lt;/code&gt;  的元素&lt;/h4&gt;
&lt;p&gt;在 tuple 变量使用&lt;strong&gt;点标记法&lt;/strong&gt;，后接元素的索引号&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;println!&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&amp;#123;&amp;#125; &amp;#123;&amp;#125; &amp;#123;&amp;#125;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; tup&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;O&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; tup&lt;span class=&#34;token number&#34;&gt;.1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; tup&lt;span class=&#34;token number&#34;&gt;.2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;数组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数组&#34;&gt;#&lt;/a&gt; 数组&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;数组也可以将多个值放在一个类型里&lt;/li&gt;
&lt;li&gt;数组中每个元素的类型必须相同&lt;/li&gt;
&lt;li&gt;数组的长度也是固定的&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;数组没有  &lt;code&gt;Vector&lt;/code&gt;  灵活，如果想让你的数据存放在 stack（栈）上而不是 heap（堆）上，或者想保证有固定数量的元素，这时使用数组更有好处&lt;/p&gt;
&lt;h4 id=&#34;数组的类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数组的类型&#34;&gt;#&lt;/a&gt; 数组的类型&lt;/h4&gt;
&lt;p&gt;数组的类型以这种形式表示： &lt;code&gt;[类型;长度]&lt;/code&gt;&lt;/p&gt;
&lt;h4 id=&#34;声明一个数组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#声明一个数组&#34;&gt;#&lt;/a&gt; 声明一个数组&lt;/h4&gt;
&lt;p&gt;两种方法：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在中括号里，各值用逗号分开&lt;/li&gt;
&lt;li&gt;如果数组的每个元素值都相同，那么可以定义为： &lt;code&gt;[初始值;长度]&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;51&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;［&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 它就相当于：let a= ［3, 3, 3, 3, 3];&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h4 id=&#34;访问数组的元素&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#访问数组的元素&#34;&gt;#&lt;/a&gt; 访问数组的元素&lt;/h4&gt;
&lt;p&gt;可以使用索引来访问数组的元素。&lt;/p&gt;
&lt;p&gt;如果访问的索引超出了数组的范围，那么：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;索引是字面量等，编译器能检查出来，编译不通过&lt;/li&gt;
&lt;li&gt;编译器没能检查出来，编译通过
&lt;ul&gt;
&lt;li&gt;运行会报错（runtime 时会 panic）&lt;/li&gt;
&lt;li&gt;Rust 不会允许其继续访问相应地址的内存&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;基础控制流&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#基础控制流&#34;&gt;#&lt;/a&gt; 基础控制流&lt;/h1&gt;
&lt;h3 id=&#34;if-else&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#if-else&#34;&gt;#&lt;/a&gt;  &lt;code&gt;if else&lt;/code&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;如下代码在 rust 编译器环境下会产生报错：&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; number &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; condition &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;else&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;6&#34;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;因为返回给  &lt;code&gt;number&lt;/code&gt;  的结果类型不确定！&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;match&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#match&#34;&gt;#&lt;/a&gt;  &lt;code&gt;match&lt;/code&gt;&lt;/h3&gt;
&lt;h2 id=&#34;循环&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#循环&#34;&gt;#&lt;/a&gt; 循环&lt;/h2&gt;
&lt;h3 id=&#34;loop&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#loop&#34;&gt;#&lt;/a&gt;  &lt;code&gt;loop&lt;/code&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;没有条件判断&lt;/li&gt;
&lt;li&gt;使用  &lt;code&gt;break&lt;/code&gt;  跳出循环&lt;/li&gt;
&lt;li&gt;&lt;code&gt;loop&lt;/code&gt;  有返回值，为  &lt;code&gt;break&lt;/code&gt;  后面的表达式&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; result &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;loop&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token keyword&#34;&gt;break&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;expression&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;while&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#while&#34;&gt;#&lt;/a&gt;  &lt;code&gt;while&lt;/code&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;while&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;和其他语言差别不大&lt;/p&gt;
&lt;h3 id=&#34;for&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#for&#34;&gt;#&lt;/a&gt;  &lt;code&gt;for&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;比  &lt;code&gt;loop&lt;/code&gt;  和  &lt;code&gt;while&lt;/code&gt;  更适合遍历容器，更安全、高效&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// eg:&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;10&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;20&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;30&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;40&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;50&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; element &lt;span class=&#34;token keyword&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;aiter&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token macro property&#34;&gt;println!&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;the value is: &amp;#123;&amp;#125;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; element&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;所有权-ownership&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#所有权-ownership&#34;&gt;#&lt;/a&gt; 所有权  &lt;code&gt;Ownership&lt;/code&gt;&lt;/h1&gt;
&lt;h2 id=&#34;什么是所有权&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#什么是所有权&#34;&gt;#&lt;/a&gt; 什么是所有权&lt;/h2&gt;
&lt;p&gt;Rust 的&lt;strong&gt;核心特性&lt;/strong&gt;就是所有权&lt;/p&gt;
&lt;p&gt;所有程序在运行时都必须管理它们使用的计算机内存&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;有些语言有垃圾收集机制 (GC)，在程序运行时，它们会不断地寻找不再使用的内存&lt;/li&gt;
&lt;li&gt;还有一些语言，程序员必须显式地分配和释放内存 (eg: C)&lt;/li&gt;
&lt;li&gt;Rust 采用了第三种方式：
&lt;ul&gt;
&lt;li&gt;内存是通过一个&lt;strong&gt;所有权系统&lt;/strong&gt;来管理的，其中包含一组编译器在编译时检查的规则&lt;/li&gt;
&lt;li&gt;当程序运行时，所有权特性不会减慢程序的运行速度，因为 Rust 的所有权系统将将内存的管理提前到了编译阶段&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;在像 Rust 这样的系统级编程语言里，一个值是在 stack 上还是在 heap 上对语言的行和你为什么要做某些决定是有更大的影响的。&lt;mark&gt;管理 heap 数据就是所有权存在的原因。&lt;/mark&gt;&lt;/p&gt;
&lt;h2 id=&#34;stack-vs-heap&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#stack-vs-heap&#34;&gt;#&lt;/a&gt; Stack vs Heap&lt;/h2&gt;
&lt;p&gt;在代码运行的时候，Stack 和 Heap 都是你可用的内存，但他们的结构很不相同：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Stack&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;Stack 按值的接收顺序来存储，按相反的顺序将它们移除（后进先出，LIFO）&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;添加数据叫做压入栈  &lt;code&gt;push&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;移除数据叫做弹出栈  &lt;code&gt;pop&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;所有存储在 Stack 上的数据必须拥有已知的固定的大小&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;因为指针是已知固定大小的，可以把指针存放在 stack 上。但如果想要实际数据，你必须使用指针来定位，然后访问 heap&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;把数据压到 stack 上要比在 heap 上分配快得多，因为操作系统不需要寻找用来存储新数据的空间，那个位置永远都在 stack 的顶端&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果数据存放的距离比较近，那么处理器的处理速度就会更快一些&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;Heap&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;当你把数据放入 heap 时，你会请求一定数量的空间，这个过程叫做在 heap 上进行分配，有时仅仅称 “&lt;strong&gt;分配&lt;/strong&gt;”。在 heap 上分配空间需要做&lt;strong&gt;更多的工作&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;操作系统在 heap 里找到一块足够大的空间&lt;/li&gt;
&lt;li&gt;然后要做好记录方便下次分配，把它标记为在用&lt;/li&gt;
&lt;li&gt;并返回一个&lt;strong&gt;指针&lt;/strong&gt;，也就是这个空间的地址&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;编译时大小未知的数据或运行时大小可能发生变化的数据必须存放在 heap 上&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;如果数据之间的距离比较远，那么处理速度就会慢一些&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;所有权解决的问题：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;跟踪代码的哪些部分正在使用 heap 的哪些数据&lt;/li&gt;
&lt;li&gt;最小化 heap 上的重复数据量&lt;/li&gt;
&lt;li&gt;清理 heap 上未使用的数据以避免空间不足。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;掌握了所有权，那么就不需要经常去想 stack 或 heap 了&lt;/p&gt;
&lt;h2 id=&#34;所有权规则&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#所有权规则&#34;&gt;#&lt;/a&gt; 所有权规则&lt;/h2&gt;
&lt;h3 id=&#34;三条规则&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三条规则&#34;&gt;#&lt;/a&gt; 三条规则&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;每个值都有一个变量，这个变量是该值的所有者&lt;/li&gt;
&lt;li&gt;每个值同时只能有一个所有者&lt;/li&gt;
&lt;li&gt;当所有者超出作用域（scope）时
&lt;ul&gt;
&lt;li&gt;它拥有它的值的所有权，就会被  &lt;code&gt;drop&lt;/code&gt;  函数清理 (heap 上的数据)&lt;/li&gt;
&lt;li&gt;它没有它的值的所有权，不会清理&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;返回值与作用域&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#返回值与作用域&#34;&gt;#&lt;/a&gt; 返回值与作用域&lt;/h3&gt;
&lt;p&gt;函数在返回值的过程中同样也会发生所有权的转移，返回表达式的值的所有权将转移到函数结果所赋值的变量上&lt;/p&gt;
&lt;h2 id=&#34;复制-copy-trait&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#复制-copy-trait&#34;&gt;#&lt;/a&gt; 复制  &lt;code&gt;Copy trait&lt;/code&gt;&lt;/h2&gt;
&lt;p&gt;用于像整数这样完全存放在 stack 上面不包含 heap 上的简单数据类型（标量）&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;如果一个类型实现了  &lt;code&gt;Copy&lt;/code&gt;  这个  &lt;code&gt;trait&lt;/code&gt; ，那么旧的变量在赋值后仍然可用&lt;/li&gt;
&lt;li&gt;如果一个类型或者该类型的一部分实现了  &lt;code&gt;Drop trait&lt;/code&gt;  ，那么 Rust 不允许让它再去实现  &lt;code&gt;Copy trait&lt;/code&gt;  了&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; x &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; y &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; x&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;//x 和 y 都是有效的&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;println!&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&amp;#123;&amp;#125; &amp;#123;&amp;#125;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; x&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;移动-move&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#移动-move&#34;&gt;#&lt;/a&gt; 移动  &lt;code&gt;Move&lt;/code&gt;&lt;/h2&gt;
&lt;p&gt;多个变量可以与同一个数据使用一种独特的方式  &lt;code&gt;Move&lt;/code&gt;  来交互&lt;/p&gt;
&lt;p&gt;以  &lt;code&gt;String&lt;/code&gt;  类型为例&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;hello&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s2 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; s1&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;当把  &lt;code&gt;s1&lt;/code&gt;  赋给  &lt;code&gt;s2&lt;/code&gt; ， &lt;code&gt;String&lt;/code&gt;  在 stack 上的数据被复制了一份，heap 内容不变&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/cs/rust/string-move.png&#34; alt=&#34;string-move&#34; /&gt;&lt;/p&gt;
&lt;p&gt;当  &lt;code&gt;s1&lt;/code&gt;  、 &lt;code&gt;s2&lt;/code&gt;  离开作用域时，它们都会尝试释放相同的内存，就会导致&lt;strong&gt;二次释放 (double free) bug&lt;/strong&gt; 。为了避免这个问题，Rust 会让原来的  &lt;code&gt;s1&lt;/code&gt;  &lt;strong&gt;失效&lt;/strong&gt; ，此后当 s1・离开作用域的时候，Rust 不需要释放任何东西。&lt;/p&gt;
&lt;p&gt;&lt;code&gt;s1&lt;/code&gt;  此后处于  &lt;code&gt;moved&lt;/code&gt;  状态，即失效。&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;ul&gt;
&lt;li&gt;浅拷贝（shallow copy）
&lt;ul&gt;
&lt;li&gt;只拷贝 stack 上的数据，有可能产生二次释放 (double free) bug&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;深拷贝（deep copy）
&lt;ul&gt;
&lt;li&gt;同时拷贝 stack 和 heap 上的数据&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;Rust 中采用的是第三种 “拷贝”，也就是 ** 移动  &lt;code&gt;Move&lt;/code&gt;  **，在浅拷贝的基础上让原来的 stack 数据失效。&lt;/p&gt;
&lt;p&gt;这体现了 Rust 隐含的一个设计原则：Rust 不会自动创建数据的深拷贝。就运行时性能而言，任何自动赋值的操作都是廉价的。&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;克隆-clone&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#克隆-clone&#34;&gt;#&lt;/a&gt; 克隆  &lt;code&gt;CLone&lt;/code&gt;&lt;/h2&gt;
&lt;p&gt;针对包含 heap 数据的矢量数据类型，相当于深拷贝&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Hello&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s2 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; s1&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;clone&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;/assets/cs/rust/string-clone.png&#34; alt=&#34;string-clone&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;引用-reference&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#引用-reference&#34;&gt;#&lt;/a&gt; 引用  &lt;code&gt;Reference&lt;/code&gt;&lt;/h2&gt;
&lt;p&gt;&lt;code&gt;&amp;amp;&lt;/code&gt;  符号就表示引用，允许引用该值而不取得其所有权；&lt;/p&gt;
&lt;p&gt;对应的解引用符号是  &lt;code&gt;*&lt;/code&gt;&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;和 C/C++ 一样，Rust 引用是符号是  &lt;code&gt;&amp;amp;&lt;/code&gt;  ，解引用符号是  &lt;code&gt;*&lt;/code&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/cs/rust/string-reference.png&#34; alt=&#34;string-reference&#34; /&gt;&lt;/p&gt;
&lt;p&gt;Rust 中的引用在任何给定的时刻，引用必须一直有效 (非悬空引用)，只能满足下列条件之一：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;一个可变的引用&lt;/li&gt;
&lt;li&gt;任意数量不可变的引用&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;可变引用-mutable-reference&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#可变引用-mutable-reference&#34;&gt;#&lt;/a&gt; 可变引用  &lt;code&gt;Mutable Reference&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;Rust 支持&lt;strong&gt;可变引用&lt;/strong&gt; ，用  &lt;code&gt;&amp;amp;mut&lt;/code&gt;  符号代替  &lt;code&gt;&amp;amp;&lt;/code&gt;  即为可变引用。&lt;/p&gt;
&lt;p&gt;但是可变引用有以下几个限制：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;在特定作用域内，对于某一块数据，只能有一个可变引用&lt;/li&gt;
&lt;li&gt;不可以同时拥有可变引用和不可变引用&lt;/li&gt;
&lt;li&gt;（多个不变的引用是可以的）&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;第一个限制的好处是可在编译时防止数据竞争。违反将出现如下报错：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;span&gt;bash&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;error&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;E0499&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;: cannot borrow &lt;span class=&#34;token string&#34;&gt;&#39;xxx&#39;&lt;/span&gt; as mutable &lt;span class=&#34;token function&#34;&gt;more&lt;/span&gt; than once at a &lt;span class=&#34;token function&#34;&gt;time&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;第二个限制避免了可变引用对不可变引用的影响。违反将出现如下报错：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;span&gt;bash&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;error&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;E0502&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;: cannot borrow &lt;span class=&#34;token string&#34;&gt;&#39;xxx&#39;&lt;/span&gt; as mutable because it is also borrowed as immutable&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;::: infromation&lt;/p&gt;
&lt;p&gt;以下三种行为下会发生数据竞争：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;两个或多个指针同时访问同一个数据&lt;/li&gt;
&lt;li&gt;至少有一个指针用于写入数据&lt;/li&gt;
&lt;li&gt;没有使用任何机制来同步对数据的访问&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;数据竞争在运行时是很难发现的（C/C++ 里经常出现），所以 Rust 从根本上避免了这种问题来保证运行时的安全性&lt;/p&gt;
&lt;p&gt;:::&lt;/p&gt;
&lt;p&gt;可以通过创建新的作用域，来允许&lt;strong&gt;非同时&lt;/strong&gt;的创建&lt;strong&gt;多个可变引用&lt;/strong&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;fn&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;main&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;mut&lt;/span&gt; s &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt; from &lt;span class=&#34;token string&#34;&gt;&#34;Hello&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	  &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;mut&lt;/span&gt; s&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;	&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s2 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;mut&lt;/span&gt; s&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;悬空引用-dangling-reference&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#悬空引用-dangling-reference&#34;&gt;#&lt;/a&gt; 悬空引用  &lt;code&gt;Dangling Reference&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;也叫悬垂引用，在 Rust 里，编译器可保证引用永远都不是悬空引用。﻿﻿如果你引用了某些数据，编译器将保证在引用离开作用域之前数据不会离开作用域。对于任何出现的悬空引用， Rust 在编译阶段就会报错：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;span&gt;bash&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;error&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;E0106&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;: missing lifetime specifier&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;悬空指针（Dangling Pointer）：一个指针引用了内存中的某个地址，而这块内存可能已经释放并分配给其它人使用了。&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;借用-borrow&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#借用-borrow&#34;&gt;#&lt;/a&gt; 借用  &lt;code&gt;Borrow&lt;/code&gt;&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;引用作为函数参数&lt;/strong&gt;这个行为叫做&lt;strong&gt;借用&lt;/strong&gt; ，本质上就是引用。&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;fn&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;main&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;mut&lt;/span&gt; s1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Hello&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; len &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;calculate_length&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;mut&lt;/span&gt; s1&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token macro property&#34;&gt;println!&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;The length of &#39;&amp;#123;&amp;#125;&#39; is &amp;#123;&amp;#125;.&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; s1&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; len&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;fn&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;calculate_length&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;s&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;mut&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;-&gt;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;usize&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  s&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;push_str&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;, world&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  s&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;len&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;切片类型-slice&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#切片类型-slice&#34;&gt;#&lt;/a&gt; 切片类型  &lt;code&gt;slice&lt;/code&gt;&lt;/h2&gt;
&lt;p&gt;Rust 的另外一种不持有所有权的数据类型&lt;/p&gt;
&lt;h3 id=&#34;字符串切片&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#字符串切片&#34;&gt;#&lt;/a&gt; 字符串切片&lt;/h3&gt;
&lt;p&gt;字符串切片是指向字符串中一部分内容的引用&lt;/p&gt;
&lt;p&gt;形式：  &lt;code&gt;[开始索引..结束索引]&lt;/code&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;开始索引就是切片起始位置的索引值，若不写则默认为 0&lt;/li&gt;
&lt;li&gt;结束索引是切片终止位置的下一个索引值，若不写则默认为 String 的 Capacity&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;fn&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;main&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;Hello world&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; hello &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;s&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;// 左闭右开&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; world &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;s&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;6&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;11&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;// 左闭右开&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img data-src=&#34;/assets/cs/rust/string-slice.jpeg&#34; alt=&#34;string-slice&#34; /&gt;&lt;/p&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;字符串切片的范围索引必须发生在有效的 UTF-8 字符边界内&lt;/p&gt;
&lt;p&gt;如果尝试从一个多字节的字符中创建字符串切片，程序会报错并退出&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;字符串字面值实际上就是字符串切片  &lt;code&gt;String slice&lt;/code&gt;&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;//s 的类型是 &amp;amp;str&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#34;Hello, World!&#34;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;⭐️ 将字符串切片作参数传递&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;fn&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;first_words&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;-&gt;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;str&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;对于这样接受字符串作为参数的函数，有经验的 Rust 开发者会采用  &lt;code&gt;&amp;amp;str&lt;/code&gt;  作为参数类型，因这样就可以同时接收 String&lt;br /&gt;
 和 &amp;amp;str 类型的参数了：&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;fn&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;first_words&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;str&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;-&gt;&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;str&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ul&gt;
&lt;li&gt;使用字符串切片，直接作为参数调用该函数  &lt;code&gt;first_words(mystr)&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;使用 String，可以创建一个完整的 String 切片作为参数来调用该函数  &lt;code&gt;firstwords(&amp;amp;mystr[..])&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;定义函数时使用字符串切片来代替字符串引用会使我们的 API 更加通用，且不会损失任何功能。&lt;/p&gt;
&lt;h3 id=&#34;数组切片&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数组切片&#34;&gt;#&lt;/a&gt; 数组切片&lt;/h3&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; a &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;4&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;5&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; slice &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;&amp;amp;&lt;/span&gt;a&lt;span class=&#34;token punctuation&#34;&gt;[&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;..&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;]&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h1 id=&#34;矢量变量&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#矢量变量&#34;&gt;#&lt;/a&gt; 矢量变量&lt;/h1&gt;
&lt;h2 id=&#34;string-类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#string-类型&#34;&gt;#&lt;/a&gt; String 类型&lt;/h2&gt;
&lt;p&gt;&lt;strong&gt;字符串字面值&lt;/strong&gt;是程序里手写的那些字符串值，它们是不可变的、硬编码的。&lt;/p&gt;
&lt;p&gt;Rust 还有第二种字符串类型： &lt;code&gt;Sting&lt;/code&gt;  。&lt;/p&gt;
&lt;p&gt;String 比那些基础标量数据类型更复杂，在 heap 上分配。能够存储在编译时未知数量的文本。&lt;/p&gt;
&lt;h3 id=&#34;数据结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#数据结构&#34;&gt;#&lt;/a&gt; 数据结构&lt;/h3&gt;
&lt;p&gt;一个 String 由 stack 上的 3 部分组成：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;一个指向存放字符串内容的内存的指针&lt;/li&gt;
&lt;li&gt;长度 len，就是存放字符串内容所需的字节数&lt;/li&gt;
&lt;li&gt;容量 capacity ，是 String 从操作系统总共获得内存的总字节数&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;存放字符串内容的部分在 heap 上&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/cs/rust/string%22hello%22.png&#34; alt=&#34;string&amp;quot;hello&amp;quot;&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;创建-string-类型的值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#创建-string-类型的值&#34;&gt;#&lt;/a&gt; 创建  &lt;code&gt;String&lt;/code&gt;  类型的值&lt;/h3&gt;
&lt;p&gt;可以使用  &lt;code&gt;from&lt;/code&gt;  函数从字符串字面值创建出  &lt;code&gt;String&lt;/code&gt;  类型&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; s &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;hello&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;code&gt;::&lt;/code&gt;  表示  &lt;code&gt;from&lt;/code&gt;  是  &lt;code&gt;String&lt;/code&gt;  类型下的函数&lt;/p&gt;
&lt;p&gt;这类字符串是可以被修改的&lt;/p&gt;
&lt;h2 id=&#34;vector-类型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vector-类型&#34;&gt;#&lt;/a&gt;  &lt;code&gt;Vector&lt;/code&gt;  类型&lt;/h2&gt;
&lt;h1 id=&#34;struct&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#struct&#34;&gt;#&lt;/a&gt;  &lt;code&gt;struct&lt;/code&gt;&lt;/h1&gt;
&lt;h2 id=&#34;struct-基础操作&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#struct-基础操作&#34;&gt;#&lt;/a&gt;  &lt;code&gt;struct&lt;/code&gt;  基础操作&lt;/h2&gt;
&lt;h3 id=&#34;定义-struct&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#定义-struct&#34;&gt;#&lt;/a&gt; 定义  &lt;code&gt;struct&lt;/code&gt;&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;使用  &lt;code&gt;struct&lt;/code&gt;  关键字，并內整个  &lt;code&gt;struct&lt;/code&gt;  命名&lt;/li&gt;
&lt;li&gt;在花括号内，为所有字段（Field）定义名称和类型&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token type-definition class-name&#34;&gt;User&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  username&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  email&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  sign_in_count&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;u64&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  active&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;bool&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;实例化-struct&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实例化-struct&#34;&gt;#&lt;/a&gt; 实例化  &lt;code&gt;struct&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;想要使用  &lt;code&gt;struct&lt;/code&gt; ，需要创建  &lt;code&gt;struct&lt;/code&gt;  的实例：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;为&lt;strong&gt;每个&lt;/strong&gt;字段指定具体值&lt;/li&gt;
&lt;li&gt;无需按声明的顺序进行指定&lt;/li&gt;
&lt;/ul&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; user1 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;User&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  email&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;someone@example.com&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  username&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;someusername123&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  active&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  sign_in_count&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;一旦  &lt;code&gt;struct&lt;/code&gt;  的实例是可变的，那么实例中所有的字段都是可变的&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;取得-struct-里面的某个值&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#取得-struct-里面的某个值&#34;&gt;#&lt;/a&gt; 取得  &lt;code&gt;struct&lt;/code&gt;  里面的某个值&lt;/h3&gt;
&lt;p&gt;使用点标记法：&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;user1&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;email &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;anotheremail@example.com&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;字段初始化简写&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#字段初始化简写&#34;&gt;#&lt;/a&gt; 字段初始化简写&lt;/h3&gt;
&lt;p&gt;当&lt;strong&gt;字段名与字段值对应变量名相同&lt;/strong&gt;时，就可以使用字段初始化简写的方式：&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;fn&lt;/span&gt; &lt;span class=&#34;token function-definition function&#34;&gt;build_user&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;email&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; username&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;-&gt;&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;User&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token class-name&#34;&gt;User&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    email&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    username&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    active&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token boolean&#34;&gt;true&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    sign_in_count&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;struct-更新语法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#struct-更新语法&#34;&gt;#&lt;/a&gt;  &lt;code&gt;struct&lt;/code&gt;  更新语法&lt;/h3&gt;
&lt;p&gt;当你想基于某个  &lt;code&gt;struct&lt;/code&gt;  实例来创建一个新实例的时候，可以使用  &lt;code&gt;struct&lt;/code&gt;  更新语法：&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 不使用 struct 更新语法&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; user2 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;User&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  email&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;another@example.com&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  username&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;anotherusername567&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  active&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; user1&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;active&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  sign_in_count&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; user1&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;sign_in_count&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;// 使用 struct 更新语法&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; user2 &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;User&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  email&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;::&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;another@example.com&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  username&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;anotherusername567&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token punctuation&#34;&gt;..&lt;/span&gt;user1&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;debug-阶段打印-struct&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#debug-阶段打印-struct&#34;&gt;#&lt;/a&gt; debug 阶段打印  &lt;code&gt;struct&lt;/code&gt;&lt;/h3&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token attribute attr-name&#34;&gt;#[derive(Debug)]&lt;/span&gt; &lt;span class=&#34;token comment&#34;&gt;// 添加注解，表示派生自 Debug 这个 trait&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;...&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;println!&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&amp;#123;:?&amp;#125;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; mystruct&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;// 输出为一行，不够清晰直观&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token macro property&#34;&gt;println!&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#34;&amp;#123;:#?&amp;#125;&#34;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; mystruct&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;span class=&#34;token comment&#34;&gt;// 输出结构化信息，更清晰直观&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h2 id=&#34;struct-数据的所有权&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#struct-数据的所有权&#34;&gt;#&lt;/a&gt;  &lt;code&gt;struct&lt;/code&gt;  数据的所有权&lt;/h2&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token type-definition class-name&#34;&gt;User&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  username&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  email&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;String&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  sign_in_count&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;u64&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  active&lt;span class=&#34;token punctuation&#34;&gt;:&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;bool&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;这里的字段使用了 String 而不是 &amp;amp;str：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;struct&lt;/code&gt;  实例拥有其所有的数据&lt;/li&gt;
&lt;li&gt;只要  &lt;code&gt;struct&lt;/code&gt;  实例是有效的，那么里面的字段数据也是有效的&lt;/li&gt;
&lt;li&gt;&lt;code&gt;struct&lt;/code&gt;  里也可以存放引用，但这需要使用生命周期&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;struct-的方法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#struct-的方法&#34;&gt;#&lt;/a&gt;  &lt;code&gt;struct&lt;/code&gt;  的方法&lt;/h2&gt;
&lt;p&gt;Rust 是一个多范式的语言，也支持面向对象编程&lt;/p&gt;
&lt;p&gt;Rust 方法与函数不同之处：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;方法是在  &lt;code&gt;struct&lt;/code&gt; （或  &lt;code&gt;enum&lt;/code&gt;  、 &lt;code&gt;trait&lt;/code&gt;  对象）的上下文中定义&lt;/li&gt;
&lt;li&gt;第一个参数是   &lt;code&gt;self&lt;/code&gt;  ，表示方法被调用的  &lt;code&gt;struct&lt;/code&gt;  实例&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;struct-扩展定义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#struct-扩展定义&#34;&gt;#&lt;/a&gt;  &lt;code&gt;struct&lt;/code&gt;  扩展定义&lt;/h2&gt;
&lt;h3 id=&#34;tuple-struct&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#tuple-struct&#34;&gt;#&lt;/a&gt;  &lt;code&gt;tuple struct&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;Rust 可定义类似  &lt;code&gt;tuple&lt;/code&gt;  的  &lt;code&gt;struct&lt;/code&gt; ，叫做  &lt;code&gt;tuple struct&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;code&gt;﻿﻿Tuple struct&lt;/code&gt;  整体有个名字，但里面的元素没有名字&lt;/p&gt;
&lt;p&gt;适用于想给整个  &lt;code&gt;tuple&lt;/code&gt;  起名，并让它不同于其它  &lt;code&gt;tuple &lt;/code&gt; ，而且又不需要给每个元素起名&lt;/p&gt;
&lt;h4 id=&#34;定义-tuple-struct&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#定义-tuple-struct&#34;&gt;#&lt;/a&gt; 定义  &lt;code&gt;tuple struct&lt;/code&gt;&lt;/h4&gt;
&lt;p&gt;使用  &lt;code&gt;struct&lt;/code&gt;  关键字，后边是名字，以及里面元素的类型&lt;/p&gt;
&lt;figure class=&#34;highlight rust&#34;&gt;&lt;figcaption data-lang=&#34;rust&#34;&gt;&lt;span&gt;rust&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token type-definition class-name&#34;&gt;Color&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;struct&lt;/span&gt; &lt;span class=&#34;token type-definition class-name&#34;&gt;Point&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;i32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; black &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Color&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; origin &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token class-name&#34;&gt;Point&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token comment&#34;&gt;//black 和 origin 是不同的类型，是不同 tuple struct 的实例&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;h3 id=&#34;unit-like-struct&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#unit-like-struct&#34;&gt;#&lt;/a&gt;  &lt;code&gt;Unit-Like Struct&lt;/code&gt;&lt;/h3&gt;
&lt;p&gt;可以定义没有任何字段的 struct，叫做 Unit-Like struct（因为与空元组  &lt;code&gt;()&lt;/code&gt;  也就是单元类型类似）&lt;/p&gt;
&lt;p&gt;适用于需要在某个类型上实现某个 trait，但是在里面又没有想要存储的数据&lt;/p&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;操作系统的定义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#操作系统的定义&#34;&gt;#&lt;/a&gt; 操作系统的定义&lt;/h1&gt;
&lt;p&gt;实际上操作系统没有普遍接受的定义&lt;/p&gt;
&lt;p&gt;操作系统 （Operating System,OS）是指&lt;strong&gt;控制&lt;/strong&gt;和&lt;strong&gt;管理&lt;/strong&gt;整个计算机系统的&lt;strong&gt;硬件和软件资源&lt;/strong&gt;，并合理地&lt;strong&gt;组织调度&lt;/strong&gt;计算机的&lt;strong&gt;工作&lt;/strong&gt;和&lt;strong&gt;资源&lt;/strong&gt;的&lt;strong&gt;分配&lt;/strong&gt;；以提供给&lt;strong&gt;用户&lt;/strong&gt;和&lt;strong&gt;其他软件&lt;/strong&gt;方便的&lt;strong&gt;接口&lt;/strong&gt;和&lt;strong&gt;环境&lt;/strong&gt;；它是计算机系统中&lt;strong&gt;最基本的系统软件&lt;/strong&gt;。&lt;/p&gt;
&lt;h1 id=&#34;操作系统的功能和目标&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#操作系统的功能和目标&#34;&gt;#&lt;/a&gt; 操作系统的功能和目标&lt;/h1&gt;
&lt;h2 id=&#34;作为系统资源的管理者&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#作为系统资源的管理者&#34;&gt;#&lt;/a&gt; 作为系统资源的管理者&lt;/h2&gt;
&lt;h3 id=&#34;提供的功能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#提供的功能&#34;&gt;#&lt;/a&gt; 提供的功能&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;处理机管理&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;存储器管理&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;文件管理&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;设备管理&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;目标&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#目标&#34;&gt;#&lt;/a&gt; 目标&lt;/h3&gt;
&lt;p&gt;安全、高效&lt;/p&gt;
&lt;h2 id=&#34;向上层提供方便易用的服务&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#向上层提供方便易用的服务&#34;&gt;#&lt;/a&gt; 向上层提供方便易用的服务&lt;/h2&gt;
&lt;h3 id=&#34;gui&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#gui&#34;&gt;#&lt;/a&gt; GUI&lt;/h3&gt;
&lt;p&gt;(Graphical User Interface) 图形化用户接口&lt;/p&gt;
&lt;h3 id=&#34;cli&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cli&#34;&gt;#&lt;/a&gt; CLI&lt;/h3&gt;
&lt;p&gt;(Command Line Interface) 命令行接口&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;联机命令接口 = 交互式命令接口&lt;/li&gt;
&lt;li&gt;脱机命令接口 = 批处理命令接口&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;程序接口&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#程序接口&#34;&gt;#&lt;/a&gt; 程序接口&lt;/h3&gt;
&lt;p&gt;可以在程序中进行&lt;strong&gt;系统调用&lt;/strong&gt;来使用程序接口。普通用户不能直接使用程序接口，只能通过程序代码&lt;strong&gt;间接&lt;/strong&gt;使用。&lt;/p&gt;
&lt;p&gt;软件和程序员才能使用程序接口&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;封装思想：操作系统把一些丑陋的硬件功能封装成简单易用的服务，使用户能更方便地使用计算机，用户无需关心底层硬件的原理，只需要对操作系统发出命令即可&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;作为最接近硬件的层次&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#作为最接近硬件的层次&#34;&gt;#&lt;/a&gt; 作为最接近硬件的层次&lt;/h2&gt;
&lt;p&gt;目标：实现&lt;strong&gt;对硬件机器的拓展&lt;/strong&gt;&lt;/p&gt;
&lt;p&gt;没有任何软件支持的计算机称为&lt;strong&gt;裸机&lt;/strong&gt;。在裸机上安装的操作系统，可以提供资源管理功能和方便用户的服务功能，将裸机改造成功能更强、使用更方便的机器&lt;/p&gt;
&lt;p&gt;通常把覆盖了软件的机器成为&lt;strong&gt;扩充机器&lt;/strong&gt;，又称之&lt;strong&gt;虚拟机&lt;/strong&gt;&lt;/p&gt;
&lt;h1 id=&#34;操作系统的特征&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#操作系统的特征&#34;&gt;#&lt;/a&gt; 操作系统的特征&lt;/h1&gt;
&lt;h2 id=&#34;并发&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#并发&#34;&gt;#&lt;/a&gt; 并发&lt;/h2&gt;
&lt;p&gt;并发：指两个或多个事件在同一时间间隔内发生。这些事件&lt;strong&gt;宏观&lt;/strong&gt;上是同时发生的，但&lt;strong&gt;微观&lt;/strong&gt;上是交替发生的&lt;/p&gt;
&lt;p&gt;操作系统的并发性：计算机系统中 “同时” 运行着多个程序，这些程序宏观上看是同时运行着的，而微观上看是交替运行的。&lt;/p&gt;
&lt;p&gt;操作系统就是伴随着 “多道程序技术” 而出现的。因此，操作系统和程序并发是一起诞生的。&lt;/p&gt;
&lt;p&gt;注意（重要考点）：单核 CPU 同一时刻只能执行一个程序，各个程序只能并发地执行多核 CPU 同一时刻可以同时执行多个程序，多个程序可以并行地执行&lt;/p&gt;
&lt;h2 id=&#34;共享&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#共享&#34;&gt;#&lt;/a&gt; 共享&lt;/h2&gt;
&lt;p&gt;共享即资源共享，是指系统中的资源可供内存中多个并发执行的进程共同使用。&lt;/p&gt;
&lt;h3 id=&#34;互斥共享方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#互斥共享方式&#34;&gt;#&lt;/a&gt; 互斥共享方式&lt;/h3&gt;
&lt;p&gt;系统中的某些资源，虽然可以提供给多个进程使用，但一个时间段内只允许一个进程访问该资源&lt;/p&gt;
&lt;h3 id=&#34;同时共享方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#同时共享方式&#34;&gt;#&lt;/a&gt; 同时共享方式&lt;/h3&gt;
&lt;p&gt;系统中的某些资源，允许一个时间段内由多个进程 “同时” 对它们进行访问&lt;/p&gt;
&lt;p&gt;所谓的 “同时” 往往是宏观上的，而在微观上，这些进程可能是交替地对该资源进行访问的（即分时共享）&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;&lt;strong&gt;并发&lt;/strong&gt; 和 &lt;strong&gt;共享&lt;/strong&gt; 的关系是&lt;strong&gt;相互依存，不可分割&lt;/strong&gt;的&lt;/p&gt;
&lt;p&gt;如果失去并发性，则系统中只有一个程序正在运行，则共享性失去存在的意义；&lt;/p&gt;
&lt;p&gt;如果失去共享性，则不同的程序不能同时访问硬盘资源，就无法实现同时发送文件，也就无法并发&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;虚拟&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#虚拟&#34;&gt;#&lt;/a&gt; 虚拟&lt;/h2&gt;
&lt;p&gt;虚拟是指把一个物理上的实体变为若干个逻辑上的对应物。物理实体（前者）是实际存在的，而逻辑上对应物（后者）是用户感受到的。&lt;/p&gt;
&lt;h3 id=&#34;空分复用技术&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#空分复用技术&#34;&gt;#&lt;/a&gt; 空分复用技术&lt;/h3&gt;
&lt;p&gt;如虚拟存储器技术&lt;/p&gt;
&lt;h3 id=&#34;时分复用技术&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#时分复用技术&#34;&gt;#&lt;/a&gt; 时分复用技术&lt;/h3&gt;
&lt;p&gt;如虚拟处理器&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;&lt;strong&gt;并发&lt;/strong&gt; 和 &lt;strong&gt;共享&lt;/strong&gt; 的关系是&lt;strong&gt;相互依存，不可分割&lt;/strong&gt;的&lt;/p&gt;
&lt;p&gt;如果失去了并发性，则一个时间段内系统中只需运行一道程序，那么就失去了实现虚拟性的意义了。因此，没有并发性，就谈不上虚拟性&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;异步&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#异步&#34;&gt;#&lt;/a&gt; 异步&lt;/h2&gt;
&lt;p&gt;异步指，在多道程序环境下，允许多个程序并发执行，但由于资源有限，进程的执行不是一贯到底的，而是走走停停，以不可预知的速度向前推进，这就是进程的异步性。&lt;/p&gt;
&lt;h1 id=&#34;操作系统的发展和分类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#操作系统的发展和分类&#34;&gt;#&lt;/a&gt; 操作系统的发展和分类&lt;/h1&gt;
&lt;h2 id=&#34;手工操作阶段&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#手工操作阶段&#34;&gt;#&lt;/a&gt; 手工操作阶段&lt;/h2&gt;
&lt;h4 id=&#34;主要缺点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要缺点&#34;&gt;#&lt;/a&gt; 主要缺点&lt;/h4&gt;
&lt;p&gt;用户独占全机、&lt;strong&gt;人机速度矛盾&lt;/strong&gt;导致资源利用率极低&lt;/p&gt;
&lt;h2 id=&#34;批处理阶段&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#批处理阶段&#34;&gt;#&lt;/a&gt; 批处理阶段&lt;/h2&gt;
&lt;p&gt;引入脱机输入 / 输出技术（用外围机 + 磁带完成），并由监督程序负责控制作业的输入、输出&lt;/p&gt;
&lt;p&gt;通过外围机把程序提前存到磁带里&lt;/p&gt;
&lt;h3 id=&#34;单道批处理系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#单道批处理系统&#34;&gt;#&lt;/a&gt; 单道批处理系统&lt;/h3&gt;
&lt;h4 id=&#34;主要优点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要优点&#34;&gt;#&lt;/a&gt; 主要优点&lt;/h4&gt;
&lt;p&gt;缓解了一定程度的人机速度矛盾，资源利用率有所提升。&lt;/p&gt;
&lt;h4 id=&#34;主要缺点-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要缺点-2&#34;&gt;#&lt;/a&gt; 主要缺点&lt;/h4&gt;
&lt;p&gt;内存中仅能有一道程序运行，只有该程序运行结束之后才能调入下一道程序。&lt;/p&gt;
&lt;p&gt;CPU 有大量的时间是在空闲等待 1/0 完成。&lt;strong&gt;资源利用率依然很低&lt;/strong&gt;。&lt;/p&gt;
&lt;h3 id=&#34;多道批处理系统操作系统开始出现&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#多道批处理系统操作系统开始出现&#34;&gt;#&lt;/a&gt; 多道批处理系统（操作系统开始出现）&lt;/h3&gt;
&lt;p&gt;每次往内存中读入多道程序，操作系统正式诞生，用于支持多道程序并发运行&lt;/p&gt;
&lt;h4 id=&#34;主要优点-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要优点-2&#34;&gt;#&lt;/a&gt; 主要优点&lt;/h4&gt;
&lt;p&gt;多道程序&lt;strong&gt;并发&lt;/strong&gt;执行，共享计算机资源。&lt;strong&gt;资源利用率大幅提升&lt;/strong&gt;，CPU 和其他资源更能保持 “忙碌” 状态，系统吞吐量增大。&lt;/p&gt;
&lt;h4 id=&#34;主要缺点-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要缺点-3&#34;&gt;#&lt;/a&gt; 主要缺点&lt;/h4&gt;
&lt;p&gt;用户响应时间长，&lt;strong&gt;没有人机交互&lt;/strong&gt;功能（用户提交自己的作业之后就只能等待计算机处理完成，中间不能控制自己的作业执行。eg：无法调试程序 / 无法在程序运行过程中输入一些参数）&lt;/p&gt;
&lt;h2 id=&#34;分时操作系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分时操作系统&#34;&gt;#&lt;/a&gt; 分时操作系统&lt;/h2&gt;
&lt;p&gt;计算机以&lt;strong&gt;时间片&lt;/strong&gt;为单位&lt;strong&gt;轮流&lt;/strong&gt;为各个用户 / 作业服务，各个用户可通过终端与计算机进行交互。&lt;/p&gt;
&lt;h4 id=&#34;主要优点-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要优点-3&#34;&gt;#&lt;/a&gt; 主要优点&lt;/h4&gt;
&lt;p&gt;用户请求可以被即时响应，解决了人机交互问题。允许多个用户同时使用一台计算机，并且用户对计算机的操作相互独立，感受不到别人的存在。&lt;/p&gt;
&lt;h4 id=&#34;主要缺点-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要缺点-4&#34;&gt;#&lt;/a&gt; 主要缺点&lt;/h4&gt;
&lt;p&gt;&lt;strong&gt;不能优先处理一些紧急任务&lt;/strong&gt;。操作系统对各个用户 / 作业都是完全公平的，循环地为每个用户 / 作业服务一个时间片，不区分任务的紧急性。&lt;/p&gt;
&lt;h2 id=&#34;实时操作系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实时操作系统&#34;&gt;#&lt;/a&gt; 实时操作系统&lt;/h2&gt;
&lt;h4 id=&#34;主要优点-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#主要优点-4&#34;&gt;#&lt;/a&gt; 主要优点&lt;/h4&gt;
&lt;p&gt;能够优先响应一些紧急任务，某些紧急任务不需时间片排队。&lt;/p&gt;
&lt;p&gt;在实时操作系统的控制下，计算机系统接收到外部信号后及时进行处理，并且要在&lt;strong&gt;严格的时限内处理完事件&lt;/strong&gt;。实时操作系统的主要特点是&lt;strong&gt;及时性&lt;/strong&gt;和&lt;strong&gt;可靠性&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;硬实时系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#硬实时系统&#34;&gt;#&lt;/a&gt; 硬实时系统&lt;/h3&gt;
&lt;p&gt;必须在绝对严格的规定时间内完成处理&lt;/p&gt;
&lt;p&gt;eg: 导弹控制系统、自动驾驶系统&lt;/p&gt;
&lt;h3 id=&#34;软实时系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#软实时系统&#34;&gt;#&lt;/a&gt; 软实时系统&lt;/h3&gt;
&lt;p&gt;能接受偶尔违反时间规定&lt;/p&gt;
&lt;p&gt;如：12306 火车订票系统&lt;/p&gt;
&lt;h2 id=&#34;网络操作系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#网络操作系统&#34;&gt;#&lt;/a&gt; 网络操作系统&lt;/h2&gt;
&lt;p&gt;是伴随着计算机网络的发展而诞生的，能把网络中各个计算机有机地结合起来，实现数据传送等功能，&lt;strong&gt;实现网络中各种资源的共享（如文件共享）和各台计算机之间的通信&lt;/strong&gt;。（如：Windows NT 就是一种典型的网络操作系统，网站服务器就可以使用）&lt;/p&gt;
&lt;h2 id=&#34;分布式操作系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#分布式操作系统&#34;&gt;#&lt;/a&gt; 分布式操作系统&lt;/h2&gt;
&lt;p&gt;主要特点是分布性和并行性。系统中的各台计算机地位相同，任何工作都可以分布在这些计算机上，由它们并行、协同完成这个任务。&lt;/p&gt;
&lt;h2 id=&#34;个人计算机操作系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#个人计算机操作系统&#34;&gt;#&lt;/a&gt; 个人计算机操作系统&lt;/h2&gt;
&lt;p&gt;eg: windows、macos&lt;/p&gt;
&lt;h1 id=&#34;内核&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#内核&#34;&gt;#&lt;/a&gt; 内核&lt;/h1&gt;
&lt;p&gt;内核是操作系统最重要最核心的部分，也是最接近硬件的部分&lt;/p&gt;
&lt;p&gt;甚至可以説，一个操作系統只要有内核就够了（eg:Docker-&amp;gt; 仅需 Linux 内核）&lt;/p&gt;
&lt;p&gt;操作系统的功能未必都在内核中，如图形化用户界面 GUI&lt;/p&gt;
&lt;p&gt;由很多内核程序组成了 “操作系统内核”，或简称 “内核、（Kernel）”&lt;/p&gt;
&lt;h2 id=&#34;内核程序运行在内核态&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#内核程序运行在内核态&#34;&gt;#&lt;/a&gt; 内核程序 —— 运行在内核态&lt;/h2&gt;
&lt;p&gt;微软、苹果有一帮人负责实现操作系统，他们写的是 “内核程序”。操作系统内核作为 “管理者”，有时会让 CPU 执行一些 “特权指令”，如：内存清零指令。这些指令影响重大，只允许 “管理者”—— 即操作系统内核来使用&lt;/p&gt;
&lt;p&gt;普通程序员写的程序就是 “应用程序”，应用程序只能使用 “非特权指令”，如：加法指令、减法指令等&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;在 CPU 设计和生产的时候就划分了特权指令和非特权指令，因此 CPU 执行一条指令前就能判断出其类型&lt;/p&gt;
&lt;p&gt;CPU 中有一个寄存器叫 程序状态字寄存器（PSW），其中有个二进制位，1 表示 “内核态”，0 表示 “用户态”&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;内核态运行内核程序&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#内核态运行内核程序&#34;&gt;#&lt;/a&gt; 内核态 —— 运行内核程序&lt;/h2&gt;
&lt;p&gt;CPU 有两种状态，“内核态” 和 “用户态”。处于内核态时，说明此时正在运行的是内核程序，此时可以执行特权指令处于用户态时，说明此时正在运行的是应用程序，此时只能执行非特权指令&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;内核态 = 核心态 = 管态；用户态 = 目态&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;内核态和用户态的切换-变态&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#内核态和用户态的切换-变态&#34;&gt;#&lt;/a&gt; 内核态和用户态的切换 (变态)&lt;/h3&gt;
&lt;p&gt;变态的过程是有成本的，要消耗不少时间，频繁地变态会降低系统性能&lt;/p&gt;
&lt;h4 id=&#34;内核态-用户态&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#内核态-用户态&#34;&gt;#&lt;/a&gt; 内核态 -&amp;gt; 用户态&lt;/h4&gt;
&lt;p&gt;执行一条特权指令一一修改 PSW 的标志位为 “用户态”，这个动作意味着操作系统将主动让出 CPU 使用权&lt;/p&gt;
&lt;h4 id=&#34;用户态-内核态&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#用户态-内核态&#34;&gt;#&lt;/a&gt; 用户态 -&amp;gt; 内核态&lt;/h4&gt;
&lt;p&gt;由 “中断” 引发，硬件自动完成变态过程，触发中断信号意味着操作系统将强行夺回 CPU 的使用权。除了非法使用特权指令之外，还有很多事件会触发中断信号。一个共性是，旦凡&lt;strong&gt;需要操作系统介入的地方，都会触发中断信号&lt;/strong&gt;&lt;/p&gt;
&lt;h1 id=&#34;系统调用&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#系统调用&#34;&gt;#&lt;/a&gt; 系统调用&lt;/h1&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:center&#34;&gt;对象&lt;/th&gt;
&lt;th style=&#34;text-align:center&#34;&gt;与系统调用、库函数的关系&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;普通应用程序&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;可直接进行系统调用，也可使用库函数。 有的库函数涉及系统调用，有的不涉及&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;编程语言&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;strong&gt;向上提供库函数&lt;/strong&gt;。有时会将系统调用封装成库函数，以隐藏系统调用的一些细节，使程序员编程更加方便。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;操作系统&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;strong&gt;向上提供系统调用&lt;/strong&gt;，使得上层程序能请求内核的服务&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:center&#34;&gt;裸机&lt;/td&gt;
&lt;td style=&#34;text-align:center&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3huLS1paHF2OWdydWJ0OXVibGlqdG1pNG10dGNzMHZrb2VqejdiLmVn&#34;&gt;不涉及系统调用的库函数.eg&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;“取绝对值” 的函数&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cDovL3huLS1iYnJzN2J4NnIzNmdiMGtycGx2amNpc3VxOGRmczViLmVn&#34;&gt;涉及系统调用的库函数.eg&lt;/span&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;“创建一个新文件” 的函数&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;按功能分类&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#按功能分类&#34;&gt;#&lt;/a&gt; 按功能分类&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;设备管理
&lt;ul&gt;
&lt;li&gt;完成&lt;strong&gt;设备&lt;/strong&gt;的 &lt;strong&gt;请求 / 释放 / 启动&lt;/strong&gt; 等功能&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;文件管理
&lt;ul&gt;
&lt;li&gt;完成&lt;strong&gt;文件&lt;/strong&gt;的 &lt;strong&gt;读 / 写 / 创建 / 删除&lt;/strong&gt; 等功能&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;进程控制
&lt;ul&gt;
&lt;li&gt;完成&lt;strong&gt;进程&lt;/strong&gt;的 &lt;strong&gt;创建 / 撒销 / 阻塞 / 唤醒&lt;/strong&gt; 等功能&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;进程通信
&lt;ul&gt;
&lt;li&gt;完成&lt;strong&gt;进程&lt;/strong&gt;之间的 &lt;strong&gt;消息传递 / 信号传递&lt;/strong&gt; 等功能&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;内存管理
&lt;ul&gt;
&lt;li&gt;完成&lt;strong&gt;内存&lt;/strong&gt;的 &lt;strong&gt;分配 / 回收&lt;/strong&gt; 等功能&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;应用程序通过系统调用请求操作系统的服务。而系统中的各种共享资源都由操作系统内核统一掌管，&lt;mark&gt;因此凡是与共享资源有关的操作（如存储分配、1/0 操作、文件管理等），都必须通过系统调用的方式向操作系统内核提出服务请求&lt;/mark&gt;，由操作系统内核代为完成。这样&lt;mark&gt;可以保证系统的稳定性和安全性&lt;/mark&gt;，防止用户进行非法操作。&lt;/p&gt;
&lt;h2 id=&#34;系统调用过程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#系统调用过程&#34;&gt;#&lt;/a&gt; 系统调用过程&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;传递系统调用参数&lt;/li&gt;
&lt;li&gt;执行陷入指令（用户态）&lt;/li&gt;
&lt;li&gt;执行相应的内请求核程序处理系统调用（内核态）&lt;/li&gt;
&lt;li&gt;返回应用程序&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;陷入指令 = trap 指令 = 访管指令&lt;/p&gt;
&lt;/div&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;&lt;strong&gt;陷入指令&lt;/strong&gt;是在&lt;strong&gt;用户态&lt;/strong&gt;执行的，执行陷入指令之后立即引发一个&lt;strong&gt;内中断&lt;/strong&gt;，使 CPU 进入内核态&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;发出系统调用请求&lt;/strong&gt;是在&lt;strong&gt;用户态&lt;/strong&gt;，而&lt;strong&gt;对系统调用的相应处理&lt;/strong&gt;在&lt;strong&gt;内核态&lt;/strong&gt;下进行&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;计算计组成原理相关基础概念&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算计组成原理相关基础概念&#34;&gt;#&lt;/a&gt; 计算计组成原理相关基础概念&lt;/h1&gt;
&lt;h2 id=&#34;中断&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#中断&#34;&gt;#&lt;/a&gt; 中断&lt;/h2&gt;
&lt;p&gt;参考&lt;a href=&#34;https://fuuzen.github.io/cs/principles-of-computer-composition/exception-and-interruption/&#34;&gt;这个&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;中断&lt;/strong&gt;是让操作系统&lt;strong&gt;内核&lt;/strong&gt;夺回 CPU 使用权的&lt;strong&gt;唯一&lt;/strong&gt;途径，使 CPU 由用户态变为内核态。&lt;/p&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;没有中断就没有并发，也就没有操作系统&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/cs/os/concepts/%E4%B8%AD%E6%96%AD.png&#34; alt=&#34;中断&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;陷入指令&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#陷入指令&#34;&gt;#&lt;/a&gt; 陷入指令&lt;/h2&gt;
&lt;p&gt;执行 “陷入指令”，意味着应用程序主动地将 CPU 控制权还给操作系统内核。“系统调用” 就是通过陷入指令完成的&lt;/p&gt;
&lt;h2 id=&#34;io-输入输出系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#io-输入输出系统&#34;&gt;#&lt;/a&gt; I/O (输入输出系统)&lt;/h2&gt;
&lt;h2 id=&#34;bus-总线&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#bus-总线&#34;&gt;#&lt;/a&gt; BUS (总线)&lt;/h2&gt;
&lt;h2 id=&#34;多处理器系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#多处理器系统&#34;&gt;#&lt;/a&gt; 多处理器系统&lt;/h2&gt;
&lt;p&gt;又称并行系统、紧耦合系统&lt;/p&gt;
&lt;div class=&#34;note warning&#34;&gt;
&lt;p&gt;区分 &lt;strong&gt;多处理器系统&lt;/strong&gt; 和 &lt;strong&gt;多核系统&lt;/strong&gt; ，实际计算机往往既是多核的也是多处理器的&lt;/p&gt;
&lt;p&gt;多核和多处理器系统都用于加速计算过程。多核包含在单个 CPU 中的多个核或处理单元。多处理器由多个 CPU 组成。多核处理器不需要像多处理器那样复杂的配置。相反，多处理器更可靠并且能够运行许多程序。&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;三个优点一个缺点&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#三个优点一个缺点&#34;&gt;#&lt;/a&gt; 三个优点一个缺点？？？&lt;/h3&gt;
&lt;p&gt;老师出的作业题😅难道本来是想问多道批处理系统？而且那个也是单处理器系统啊）&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;增加吞吐量，并行处理？&lt;/li&gt;
&lt;li&gt;规模经济，降低成本，比多核处理器便宜？&lt;/li&gt;
&lt;li&gt;增加可靠性？&lt;/li&gt;
&lt;li&gt;？？？&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;非对称处理器系统&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#非对称处理器系统&#34;&gt;#&lt;/a&gt; 非对称处理器系统&lt;/h3&gt;
&lt;p&gt;非对称多处理是指一种计算机结构，其中有多个处理器，但它们并不都是一样的。这意味着，一个 CPU 可能正在处理操作系统代码，而另一个 CPU 正在执行输入和输出工作。它使用两个或更多的处理器由一个&lt;strong&gt;主处理器&lt;/strong&gt;处理。所有的 CPU 都是相互连接的，但&lt;strong&gt;不是自我调度的&lt;/strong&gt;。它用于根据任务的优先级和重要性将特定任务安排到一个 CPU。&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;非对称处理器的应用场景：被用于嵌入式系统，在这些系统中，特定任务需要并发执行，但系统不需要像对称多处理系统那样的通用计算能力&lt;/p&gt;
&lt;/div&gt;
&lt;h3 id=&#34;对称处理器系统-smp&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#对称处理器系统-smp&#34;&gt;#&lt;/a&gt; 对称处理器系统 (SMP)&lt;/h3&gt;
&lt;p&gt;SMP（Sysmmetric Multi-Processor System，对称多处理器），它由多个具有对称关系的处理器组成。所谓对称，即处理器之间&lt;strong&gt;没有主从之分&lt;/strong&gt;。SMP 架构使得一台计算机不再由单个 CPU 组成，而是由两个或更多的处理器连接到一个&lt;strong&gt;共享的主存储器&lt;/strong&gt;上，并能够共同执行任务。这些处理器通常是相同的，能够运行分配给它们的任何任务。这可以提高性能，因为任务可以在处理器之间分配，使其更快完成。&lt;/p&gt;
&lt;p&gt;对称多处理将多个 CPU 应用于一个任务，以&lt;strong&gt;并行&lt;/strong&gt;和更快的方式完成。因此，在对称多处理系统中，两个或更多的 CPU 被连接到一个共享的主存储器。同时，所有这些 CPU 都可以完全访问输入和输出设备。在对称多处理系统中，操作系统认为所有的处理器都是&lt;strong&gt;平等&lt;/strong&gt;的。&lt;/p&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;对称处理器 (SMP) 架构同时也是 UMA 架构&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;SMP 是一个紧密耦合的多处理器系统，它有一组独立运行的相同的 CPU。每个 CPU 处理不同的程序，执行不同的数据集。对称多处理系统共享公共资源，如输入设备、输出设备、内存等。&lt;/p&gt;
&lt;h2 id=&#34;多处理器环境的3种内存共享模型&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#多处理器环境的3种内存共享模型&#34;&gt;#&lt;/a&gt; 多处理器环境的 3 种内存共享模型&lt;/h2&gt;
&lt;h3 id=&#34;uma&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#uma&#34;&gt;#&lt;/a&gt; UMA&lt;/h3&gt;
&lt;p&gt;UMA（Uniform Memory Access，一致性存储器访问)，实际上就是 &lt;strong&gt;SMP&lt;/strong&gt; 。其中，&lt;mark&gt;&lt;strong&gt;一致性&lt;/strong&gt;指的就是在任意时刻，多个处理器只能为内存的每个数据保存或共享一个唯一的数值&lt;/mark&gt;。它的结构特征就是&lt;strong&gt;多处理器共享一个集中式存储器&lt;/strong&gt;，每个处理器访问存储器所需的时间一致，工作负载能够均匀的分配到所有可用处理器上，极大地提高了整个系统的数据处理能力。但是，如果多个处理器同时请求访问共享资源时，就会引发资源竞争，需要软硬件实现加锁机制来解决这个问题。&lt;/p&gt;
&lt;p&gt;因此，这样的架构设计无法拥有良好的处理器数量扩展性，因为共享内存的资源竞态总是存在的，处理器利用率最好的情况只能停留在 2 到 4 颗。&lt;/p&gt;
&lt;h3 id=&#34;numa&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#numa&#34;&gt;#&lt;/a&gt; NUMA&lt;/h3&gt;
&lt;p&gt;NUMA（Non-Uniform Memory Access，非一致性存储器访问）架构优化了 SMP 架构扩展性差以及存储器带宽窄的问题。采用了分布式存储器，将处理器和存储器划分为&lt;strong&gt;不同的节点&lt;/strong&gt;（NUMA Node），每个节点都包含了若干的处理器与内存资源。多节点的设计有效提高了存储器的带宽和处理器的扩展性。&lt;/p&gt;
&lt;p&gt;另一方面，NUMA 节点的处理器可以访问到整体存储器。按照节点内外，内存被分为：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;节点内部的本地内存&lt;/li&gt;
&lt;li&gt;节点外部的远程内存&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;当处理器访问本地内存时，走的是内部总线，当处理器访问远程内存时，走的是主板上的 QPI 互联模块。访问前者的速度要远快于后者，NUMA（非一致性存储器访问）因此而得名。&lt;/p&gt;
&lt;h3 id=&#34;coma&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#coma&#34;&gt;#&lt;/a&gt; COMA&lt;/h3&gt;
&lt;p&gt;Cache-only Memory Access (COMA) 是 ccNUMA (Cache Coherent NUMA, 缓存一致性 NUMA) 的一种演变。COMA 可以看成是专用的 NUMA，将 NUMA 中的分布式内存用高速缓存来取代。全局地址空间由高速缓存组成。访问远端的高速缓存借助分布式高速缓存目录进行。&lt;/p&gt;
&lt;h1 id=&#34;操作系统的结构&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#操作系统的结构&#34;&gt;#&lt;/a&gt; 操作系统的结构&lt;/h1&gt;
&lt;h2 id=&#34;非内核功能如gui&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#非内核功能如gui&#34;&gt;#&lt;/a&gt; 非内核功能（如 GUI）&lt;/h2&gt;
&lt;p&gt;操作系统的非内核功能运行在&lt;strong&gt;用户态&lt;/strong&gt;&lt;/p&gt;
&lt;h2 id=&#34;大-内核&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#大-内核&#34;&gt;#&lt;/a&gt; (大) 内核&lt;/h2&gt;
&lt;p&gt;内核是操作系统最基本、最核心的部分。&lt;/p&gt;
&lt;p&gt;实现操作系统内核功能的那些程序就是内核程序。&lt;/p&gt;
&lt;p&gt;操作系统内核需要运行在&lt;strong&gt;内核态&lt;/strong&gt;&lt;/p&gt;
&lt;h3 id=&#34;对系统资源进行管理的功能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#对系统资源进行管理的功能&#34;&gt;#&lt;/a&gt; 对系统资源进行管理的功能&lt;/h3&gt;
&lt;p&gt;&lt;strong&gt;大内核&lt;/strong&gt;结构中运行在&lt;strong&gt;内核态&lt;/strong&gt;，所以大内核结构操作系统变态不那么频繁&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;微内核&lt;/strong&gt;结构中运行在&lt;strong&gt;用户态&lt;/strong&gt;，所以微内核结构操作系统变态更加频繁&lt;/p&gt;
&lt;p&gt;典型的大内核 / 宏内核 / 单内核 操作系统：Linux、UNIX&lt;/p&gt;
&lt;p&gt;典型的微内核 操作系统：Windows NT&lt;/p&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;操作系统体系结构&lt;/th&gt;
&lt;th&gt;区别&lt;/th&gt;
&lt;th&gt;优点&lt;/th&gt;
&lt;th&gt;缺点&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;大内核 / 宏内核 / 单内核&lt;/td&gt;
&lt;td&gt;将操作系统的主要功能模块都作为系统内核，运行在核心态&lt;/td&gt;
&lt;td&gt;高性能&lt;/td&gt;
&lt;td&gt;内核代码庞大，结构混乱，难以维护&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;微内核&lt;/td&gt;
&lt;td&gt;只把最基本的功能保留在内核&lt;/td&gt;
&lt;td&gt;内核功能少，结构清晰，方便维护&lt;/td&gt;
&lt;td&gt;需要频繁地在核心态和用户态之间切换，性能低&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h5 id=&#34;扩展&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#扩展&#34;&gt;#&lt;/a&gt; 扩展&lt;/h5&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;&lt;/th&gt;
&lt;th&gt;特性、思想&lt;/th&gt;
&lt;th&gt;优点&lt;/th&gt;
&lt;th&gt;缺点&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;分层结构&lt;/td&gt;
&lt;td&gt;内核分多层，每层可单向调用更低一层提供的接&lt;/td&gt;
&lt;td&gt;1. 便于调试和验证，自底向上逐层调试验证&lt;/td&gt;
&lt;td&gt;1. 仅可调用相邻低层，难以合理定义各层的边界&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;2. 效率低，不可跨层调用，系统调用执行时间长&lt;/td&gt;
&lt;td&gt;2. 效率低，不可跨层调用，系统调用执行时间长&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;模块化&lt;/td&gt;
&lt;td&gt;将内核划分为多个模块，各模块之间相互协作。内核 = 主模块 ＋ 可加载内核模块&lt;/td&gt;
&lt;td&gt;1. 模块间逻辑清晰易于维护，确定模块间接口后即可多模块同时开发 2. 支持动态加载新的内核模块（如：安装设备驱动程序、安装新的文件系统模块到内核），增强 OS 适应性&lt;/td&gt;
&lt;td&gt;1. 模块间的接口定义未必合理、实用&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;主模块：只负责核心功能，如进程调度、内存管&lt;/td&gt;
&lt;td&gt;2. 支持动态加载新的内核模块（如：安装设备驱动程序、安装新的文件系统模块到内核），增强 OS 适应性&lt;/td&gt;
&lt;td&gt;2. 模块间相互依赖，更难调试和验证&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;可加载内核模块：可以动态加载新模块到内核，而无需重新编译整个内核&lt;/td&gt;
&lt;td&gt;3. 任何模块都可以直接调用其他模块，无需采用消息传递进行通信，效率高&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;宏内核 (大内核)&lt;/td&gt;
&lt;td&gt;所有的系统功能都放在内核里（大内核结构的 OS 通常也采用了 &amp;quot; 模块化” 的设计思想）&lt;/td&gt;
&lt;td&gt;性能高，内核内部各种功能都可以直接相互调用&lt;/td&gt;
&lt;td&gt;1. 内核庞大功能复杂，难以维护&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;2. 大内核中某个功能模块出错，就可能导致整个 系统崩溃&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;微内核&lt;/td&gt;
&lt;td&gt;只把中断、原语、进程通信等最核心的功能放入内核。进程管理、文件管理、设备管理等功能以用户进程的形式运行在用户态&lt;/td&gt;
&lt;td&gt;1. 内核小功能少、易于维护，内核可靠性高&lt;/td&gt;
&lt;td&gt;1. 性能低，需要频繁的切换 用户态 / 核心态。用户态下的各功能模块不可以直接相互调用，只能通过内核的 &amp;quot;消息传递&amp;quot; 来间接通信&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;2. 内核外的某个功能模块出错不会导致整个系统 崩溃&lt;/td&gt;
&lt;td&gt;2. 用户态下的各功能模块不可以直接相互调用，只能通过内核的 &amp;quot;消息传递&amp;quot; 来间接通信&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;外核 (exokernel)&lt;/td&gt;
&lt;td&gt;内核负责进程调度、进程通信等功能，外核负责为用户进程分配未经抽象的硬件资源，且由外核负责保证资源使用安全&lt;/td&gt;
&lt;td&gt;1. 外核可直接给用户进程分配 &amp;quot;不虚拟、不抽象&amp;quot; 的硬件资源，使用户进程可以更灵活的使用硬件&lt;/td&gt;
&lt;td&gt;1. 降低了系统的一致性&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;2. 减少了虚拟硬件资源的 “映射层”，提升效率&lt;/td&gt;
&lt;td&gt;2. 使系统变得更复杂&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h4 id=&#34;进程管理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#进程管理&#34;&gt;#&lt;/a&gt; 进程管理&lt;/h4&gt;
&lt;h4 id=&#34;存储器管理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#存储器管理&#34;&gt;#&lt;/a&gt; 存储器管理&lt;/h4&gt;
&lt;h4 id=&#34;设备管理等功能&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#设备管理等功能&#34;&gt;#&lt;/a&gt; 设备管理等功能&lt;/h4&gt;
&lt;h3 id=&#34;微内核&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#微内核&#34;&gt;#&lt;/a&gt; (微内核)&lt;/h3&gt;
&lt;h4 id=&#34;时钟管理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#时钟管理&#34;&gt;#&lt;/a&gt; 时钟管理&lt;/h4&gt;
&lt;p&gt;实现计时功能&lt;/p&gt;
&lt;h4 id=&#34;中断处理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#中断处理&#34;&gt;#&lt;/a&gt; 中断处理&lt;/h4&gt;
&lt;p&gt;负责实现中断机制&lt;/p&gt;
&lt;h4 id=&#34;原语设备驱动-cpu切换等&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#原语设备驱动-cpu切换等&#34;&gt;#&lt;/a&gt; 原语（设备驱动、CPU 切换等）&lt;/h4&gt;
&lt;p&gt;是一种特殊的程序，具有如下特点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;处于操作系统最底层，是最接近硬件的部分&lt;/li&gt;
&lt;li&gt;这种程序的运行具有原子性 —— 其运行只能一气呵成，不可中断&lt;/li&gt;
&lt;li&gt;运行时间较短、调用频繁&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;操作系统的引导&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#操作系统的引导&#34;&gt;#&lt;/a&gt; 操作系统的引导&lt;/h1&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/cs/os/concepts/%E6%93%8D%E4%BD%9C%E7%B3%BB%E7%BB%9F%E5%BC%95%E5%AF%BC%E8%BF%87%E7%A8%8B.png&#34; alt=&#34;操作系统引导过程&#34; /&gt;&lt;/p&gt;
&lt;p&gt;操作系统引导过程&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;CPU 从一个特定主存地址开始，取指令，执行 ROM 中的引导程序（先进行硬件自检，再开机）&lt;/li&gt;
&lt;li&gt;将磁盘的第一块 —— 主引导记录 读入内存，执行磁盘引导程序，扫描分区表&lt;/li&gt;
&lt;li&gt;从活动分区（又称主分区，即安装了操作系统的分区）读入分区引导记录，执行其中的程序&lt;/li&gt;
&lt;li&gt;从根目录下找到完整的操作系统初始化程序（即启动管理器）并执行，完成 “开机” 的一系列动作&lt;/li&gt;
&lt;/ol&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;完整的操作系统初始化程序（即启动管理器）可在根目录下找到&lt;/p&gt;
&lt;p&gt;Eg : windows 操作系统完整的开机初始化程序在  &lt;code&gt;根目录/Windows/Boot&lt;/code&gt;  下&lt;/p&gt;
&lt;/div&gt;
&lt;h1 id=&#34;虚拟机&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#虚拟机&#34;&gt;#&lt;/a&gt; 虚拟机&lt;/h1&gt;
&lt;p&gt;虚拟机：使用虚拟化技术，将一台物理机器虚拟化多台虚拟机器（Virtual Machine, VM），每个虚拟机器都可以独立运行一个操作系统&lt;/p&gt;
&lt;p&gt;同义术语：虚拟机管理程序 / 虚拟机监控程序 / Virtual Machine Monitor / Hypervisor&lt;/p&gt;
&lt;h2 id=&#34;第一类vmm&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第一类vmm&#34;&gt;#&lt;/a&gt; 第一类 VMM&lt;/h2&gt;
&lt;p&gt;直接运行在硬件上&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/cs/os/concepts/%E7%AC%AC%E4%B8%80%E7%B1%BBVMM.png&#34; alt=&#34;第一类VMM&#34; /&gt;&lt;/p&gt;
&lt;p&gt;eg: Proxmox&lt;/p&gt;
&lt;h2 id=&#34;第二类vmm&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#第二类vmm&#34;&gt;#&lt;/a&gt; 第二类 VMM&lt;/h2&gt;
&lt;p&gt;运行在宿主操作系统上&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/cs/os/concepts/%E7%AC%AC%E4%BA%8C%E7%B1%BBVMM.png&#34; alt=&#34;第二类VMM.png&#34; /&gt;&lt;/p&gt;
&lt;p&gt;eg: VMware, VirtualBox&lt;/p&gt;
&lt;h2 id=&#34;两类-vmm-的对比&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#两类-vmm-的对比&#34;&gt;#&lt;/a&gt; 两类 VMM 的对比&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;&lt;/th&gt;
&lt;th&gt;第一类 VMM&lt;/th&gt;
&lt;th&gt;第二类 VMM&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;对物理资源的控制权&lt;/td&gt;
&lt;td&gt;直接运行在硬件之上，能直接控制和分配物理资 源&lt;/td&gt;
&lt;td&gt;运行在 Host OS 之上，依赖于 Host OS 为其分配物理资源&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;资源分配方式&lt;/td&gt;
&lt;td&gt;在安装 Guest OS 时，VMM 要在原本的硬盘上自行分配存储空间，类似于 “外核” 的分配方式，分配未经抽象的物理硬件&lt;/td&gt;
&lt;td&gt;GuestOS 拥有自己的虚拟磁盘，该盘实际上是 Host OS 文件系统中的一个大文件。GuestOS 分配到的内存是虚拟内存&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;性能&lt;/td&gt;
&lt;td&gt;性能更好&lt;/td&gt;
&lt;td&gt;性能更差，需要 HostOS 作为 “中介 &amp;quot;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;可支持的虚拟机数量&lt;/td&gt;
&lt;td&gt;更多，不需要和 Host OS 竞争资源，相同的硬件资源可以支持更多的虚拟机&lt;/td&gt;
&lt;td&gt;更少，Host OS 本身需要使用物理资源，Host OS 上运行的其他进程也需要物理资源&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;虚拟机的可迁移性&lt;/td&gt;
&lt;td&gt;更差&lt;/td&gt;
&lt;td&gt;更好，只需导出虚拟机镜像文件即可迁移到另一台 HostOS 上，商业化应用更广泛&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;运行模式&lt;/td&gt;
&lt;td&gt;第一类 VMM 运行在最高特权级（Ring O），可以执行最高特权的指令；上层操作系统内核运行在次高特权级（Ring 1）；上层操作系统非内核程序程序运行在次高特权级（Ring 1）&lt;/td&gt;
&lt;td&gt;第二类 VMM 部分运行在用户态、部分运行在内核态。GuestOS 发出的系统调用会被 VMM 截获，并转化为 VMM 对 HostOS 的系统调用&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kity@2.0.4/dist/kity.min.js&#34;&gt;&lt;/script&gt;&lt;script type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/kityminder-core@1.4.50/dist/kityminder.core.min.js&#34;&gt;&lt;/script&gt;&lt;script defer=&#34;true&#34; type=&#34;text&amp;#x2F;javascript&#34; src=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.js&#34;&gt;&lt;/script&gt;&lt;link rel=&#34;stylesheet&#34; type=&#34;text&amp;#x2F;css&#34; href=&#34;https://unpkg.com/hexo-simple-mindmap@0.8.0/dist/mindmap.min.css&#34;&gt;

 &lt;h1 id=&#34;能量功率-信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#能量功率-信号&#34;&gt;#&lt;/a&gt; 能量 / 功率 信号&lt;/h1&gt;
&lt;h2 id=&#34;能量信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#能量信号&#34;&gt;#&lt;/a&gt; 能量信号&lt;/h2&gt;
&lt;p&gt;能量为一有界值，即 0 &amp;lt; &lt;em&gt;E&lt;/em&gt; &amp;lt; + ∞，此时 &lt;em&gt;P&lt;/em&gt; = 0&lt;/p&gt;
&lt;h2 id=&#34;功率信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#功率信号&#34;&gt;#&lt;/a&gt; 功率信号&lt;/h2&gt;
&lt;p&gt;功率为一有界值，即 0 &amp;lt; &lt;em&gt;P&lt;/em&gt; &amp;lt; + ∞ ，此时 &lt;em&gt;E&lt;/em&gt; = ∞&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;/assets/ie/signals-and-systems/signals-concepts/%E8%83%BD%E9%87%8F%E5%8A%9F%E7%8E%87%E4%BF%A1%E5%8F%B7.png&#34; alt=&#34;能量功率信号.png&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;连续离散-时间-信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#连续离散-时间-信号&#34;&gt;#&lt;/a&gt; 连续 / 离散 (时间) 信号&lt;/h1&gt;
&lt;div class=&#34;note information&#34;&gt;
&lt;p&gt;区分 模拟 / 数字 信号，模拟 / 数字 信号的划分是依据 “值域” 是否连续，而 连续 / 离散 时间信号的划分是依据定义域是否连续&lt;/p&gt;
&lt;p&gt;连续时间信号 &lt;strong&gt;包含&lt;/strong&gt; 模拟信号 和 数字 (量化) 信号&lt;/p&gt;
&lt;/div&gt;
&lt;h2 id=&#34;周期信号定义&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#周期信号定义&#34;&gt;#&lt;/a&gt; 周期信号定义&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;连续周期信号 : &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;T&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;f(t+mT)=f(t)&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.13889em;&#34;&gt;T&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; , &lt;em&gt;T&lt;/em&gt; 为周期 &lt;em&gt;m&lt;/em&gt; = 0,±1,±2,±3...&lt;/li&gt;
&lt;li&gt;离散周期信号 : &lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;m&lt;/mi&gt;&lt;mi&gt;N&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;k&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;f(k+mN) = f(k)&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03148em;&#34;&gt;k&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;+&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;m&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10903em;&#34;&gt;N&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03148em;&#34;&gt;k&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt; , &lt;em&gt;N&lt;/em&gt; 为周期 &lt;em&gt;m&lt;/em&gt; = 0,±1,±2,±3...&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;当&lt;em&gt; T&lt;/em&gt; 或&lt;em&gt; N&lt;/em&gt; 趋于⽆无穷时，周期信号变为⾮非周期信号。&lt;/p&gt;
&lt;h2 id=&#34;连续时间信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#连续时间信号&#34;&gt;#&lt;/a&gt; 连续时间信号&lt;/h2&gt;
&lt;p&gt;定义域连续&lt;/p&gt;
&lt;p&gt;在一定时间范围内，除若⼲不连续点之外，对任意时刻函数都有确定的函数值。 “连续” 的含义指定义域连续，⽽连续信号中可以含有不连续点。&lt;/p&gt;
&lt;h3 id=&#34;普通连续信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#普通连续信号&#34;&gt;#&lt;/a&gt; 普通连续信号&lt;/h3&gt;
&lt;p&gt;普通连续信号是指函数的定义域和值域&lt;strong&gt;没有&lt;/strong&gt;不连续点 (即跳变点) 的信号。&lt;/p&gt;
&lt;h4 id=&#34;实指数信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#实指数信号&#34;&gt;#&lt;/a&gt; (实) 指数信号&lt;/h4&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;K&lt;/mi&gt;&lt;msup&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;α&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;f (t) = Ke^{αt}
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.843556em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.07153em;&#34;&gt;K&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.843556em;&#34;&gt;&lt;span style=&#34;top:-3.113em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.0037em;&#34;&gt;α&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;指数函数求导、积分后仍为指数函数。&lt;/p&gt;
&lt;h4 id=&#34;正弦信号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#正弦信号&#34;&gt;#&lt;/a&gt; 正弦信号&lt;/h4&gt;
&lt;p&gt;利用正弦函数与余弦函数表示的信号&lt;strong&gt;统称为正弦信号&lt;/strong&gt;，可表示为&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;mi&gt;f&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;A&lt;/mi&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mi&gt;θ&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;f(t)=Acos(\omega t-\theta)
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.10764em;&#34;&gt;f&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;A&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mopen&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mbin&#34;&gt;−&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2222222222222222em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:1em;vertical-align:-0.25em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.02778em;&#34;&gt;θ&lt;/span&gt;&lt;span class=&#34;mclose&#34;&gt;)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;正弦信号求导、积分后仍然为正弦信号。&lt;/p&gt;
&lt;p&gt;指数信号可以转化为正弦信号:&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mrow&gt;&lt;msup&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mrow&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mspace linebreak=&#34;newline&#34;&gt;&lt;/mspace&gt;&lt;msup&gt;&lt;mi&gt;e&lt;/mi&gt;&lt;mrow&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/mrow&gt;&lt;/msup&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mi&gt;c&lt;/mi&gt;&lt;mi&gt;o&lt;/mi&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mi&gt;j&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;s&lt;/mi&gt;&lt;mi&gt;i&lt;/mi&gt;&lt;mi&gt;n&lt;/mi&gt;&lt;mtext&gt; &lt;/mtext&gt;&lt;mi&gt;ω&lt;/mi&gt;&lt;mi&gt;t&lt;/mi&gt;&lt;/mrow&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;e^{j\omega t}=cos\ \omega t+j\ sin\ \omega t \\
e^{-j\omega t}=cos\ \omega t-j\ sin\ \omega t
&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.874664em;vertical-align:0em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;e&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.874664em;&#34;&gt;&lt;span style=&#34;top:-3.1130000000000004em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.05724em;&#34;&gt;j&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;mord mathnormal mtight&#34;&gt;t&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.69841em;vertical-align:-0.08333em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;c&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;o&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;mspace&#34;&gt; &lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34; style=&#34;margin-right:0.03588em;&#34;&gt;ω&lt;/span&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;t&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.22