\varepsilon(t-t_0) = 
\begin{cases} 
    1 &amp;amp;  t \gt t_0 \\
    \text{undifined} &amp;amp;  t = t_0 \\
    0 &amp;amp;  t \lt t_0 
\end{cases}
\end{aligned}
